-- Schema for Domain: scheduling | Business: Media Broadcasting | Version: v1_mvm
-- Generated on: 2026-05-08 19:23:34

-- ========= DATABASE =========
CREATE DATABASE IF NOT EXISTS `media_broadcasting_ecm`.`scheduling` COMMENT 'Owns the Electronic Program Guide (EPG) and all playout scheduling logic for linear broadcast channels and on-demand programming windows. Manages dayparts, program rundowns, linear channel grids, ad pod placement, SCTE-35 cue markers, simulcast configurations, and automated schedule generation. Drives Ericsson MediaFirst automation for channel playout and failover, ensuring compliance with must-carry and blackout obligations.';

-- ========= TABLES =========
CREATE OR REPLACE TABLE `media_broadcasting_ecm`.`scheduling`.`channel` (
    `channel_id` BIGINT COMMENT 'Unique surrogate identifier for each linear broadcast channel record. Primary key for the channel master data product within the scheduling domain.',
    `billing_account_id` BIGINT COMMENT 'Foreign key linking to billing.account. Business justification: Channels have associated billing accounts for carriage fees, retransmission consent payments, and affiliate revenue. Essential for MVPD/distribution billing, carriage agreement invoicing, and per-subs',
    `broadcast_license_id` BIGINT COMMENT 'Foreign key linking to compliance.broadcast_license. Business justification: Every broadcast channel operates under a regulatory license issued by FCC/Ofcom. License terms govern transmission power, coverage area, must-carry obligations, and renewal cycles. Essential for regul',
    `cost_center_id` BIGINT COMMENT 'Foreign key linking to finance.cost_center. Business justification: Channels are cost centers in broadcast operations. Monthly financial close, P&L reporting, EBITDA analysis, and budget variance reporting all require channel-to-cost-center mapping. Standard practice ',
    `format_specification_id` BIGINT COMMENT 'Foreign key linking to mediaasset.format_specification. Business justification: Each channel has a mandated broadcast format specification (e.g., HD 1080i/50, UHD 4K HDR) governing all content aired. Scheduling and QC systems use this FK to auto-validate that scheduled asset vers',
    `genre_id` BIGINT COMMENT 'Foreign key linking to content.genre. Business justification: Channels are programmed around a primary genre (sports, kids, news, drama). Linking to content.genre enables genre-based content acquisition planning, scheduling analytics, and ad targeting configurat',
    `market_coverage_id` BIGINT COMMENT 'Foreign key linking to audience.market_coverage. Business justification: Channels operate within specific DMA/broadcast markets. Must-carry status, retransmission consent, blackout enforcement, and Nielsen station indexing are all market-specific. Linking channel to market',
    `partner_id` BIGINT COMMENT 'Foreign key linking to partner.partner_partner. Business justification: Channels are owned/operated by broadcast partners (affiliates, network operators, cable systems). Essential for affiliate management, carriage fee calculation, retransmission consent tracking, and net',
    `profit_center_id` BIGINT COMMENT 'Foreign key linking to finance.profit_center. Business justification: Channels are profit centers for revenue and cost tracking. Executive dashboards, board reporting, segment EBITDA, and management accounting all depend on channel-to-profit-center mapping. Core financi',
    `ad_break_duration_sec` STRING COMMENT 'Default duration in seconds of a standard ad pod (ad break) for this channel. Used by Wide Orbit traffic system for ad scheduling, inventory management, and avail calculation. Typical values are 120 (2 minutes) or 180 (3 minutes).',
    `affiliate_network_code` STRING COMMENT 'Code identifying the parent broadcast network or affiliate group this channel belongs to (e.g., NBC, CBS, ABC, FOX). Used for network affiliation reporting, retransmission consent negotiations, and carriage fee calculations.',
    `blackout_enabled` BOOLEAN COMMENT 'Indicates whether geographic broadcast blackout restrictions are applicable to this channel. When true, blackout rules must be enforced during playout and OTT delivery to restrict content in specific geographic markets per rights agreements.',
    `broadcast_timezone` STRING COMMENT 'IANA timezone identifier for the channels primary broadcast timezone (e.g., America/New_York, Europe/London). Governs daypart definitions, schedule generation, and EPG time display for the channels primary market.',
    `call_sign` STRING COMMENT 'Officially assigned broadcast call sign (e.g., WABC, KNBC) that uniquely identifies the station with the regulatory authority. Serves as the primary external business identifier for the channel as registered with the FCC or Ofcom.. Valid values are `^[A-Z0-9-]{2,10}$`',
    `carriage_fee_usd` DECIMAL(18,2) COMMENT 'The per-subscriber monthly carriage fee in US dollars charged to MVPDs and vMVPDs for distributing this channel. Commercially sensitive financial data used in revenue assurance, financial reconciliation in SAP S/4HANA, and EBITDA reporting.',
    `cdn_origin_url` STRING COMMENT 'The origin ingest URL configured in Akamai CDN for this channels live stream delivery. Used for OTT/streaming distribution, ABR (Adaptive Bitrate Streaming) packaging, and CDN cache configuration.',
    `channel_status` STRING COMMENT 'Current operational lifecycle state of the channel. Drives playout automation eligibility, EPG publication, and scheduling availability in Ericsson MediaFirst.. Valid values are `active|inactive|suspended|testing|decommissioned`',
    `channel_type` STRING COMMENT 'Classification of the channel by its distribution and scheduling model. Linear indicates traditional scheduled broadcast; simulcast indicates simultaneous multi-platform broadcast; pop-up indicates temporary event channel; FAST (Free Ad-Supported Streaming Television) indicates ad-supported streaming linear channel; VOD indicates on-demand programming window channel.. Valid values are `linear|simulcast|pop-up|FAST|VOD`',
    `content_rating_system` STRING COMMENT 'Default content advisory rating applied to the channels programming under the applicable rating system (e.g., US TV Parental Guidelines). Drives V-chip compliance, parental control enforcement, and COPPA-regulated childrens content restrictions.. Valid values are `TV-Y|TV-Y7|TV-G|TV-PG|TV-14|TV-MA`',
    `country_of_origin` STRING COMMENT 'ISO 3166-1 alpha-3 country code identifying the country where the channel is licensed and originates its broadcast signal (e.g., USA, GBR, DEU). Used for regulatory jurisdiction determination, rights windowing, and blackout rule enforcement.. Valid values are `^[A-Z]{3}$`',
    `created_timestamp` TIMESTAMP COMMENT 'The timestamp when this channel record was first created in the system of record. Used for data lineage, audit trail, and record lifecycle tracking in the Silver Layer lakehouse.',
    `dai_enabled` BOOLEAN COMMENT 'Indicates whether Dynamic Ad Insertion (DAI) is active for this channel, enabling server-side ad replacement for OTT/streaming delivery. Drives ad operations workflow in Wide Orbit and integration with DAI platforms.',
    `dalet_channel_code` STRING COMMENT 'The channel identifier as configured in Dalet Galaxy Media Asset Management system. Used to link this channel to content ingest workflows, metadata management, archive operations, and rundown generation in Dalet.',
    `decommission_date` DATE COMMENT 'The date on which this channel was or is scheduled to be permanently decommissioned and removed from broadcast. Nullable for active channels. Used for lifecycle management, licence surrender, and EPG removal planning.',
    `drm_enabled` BOOLEAN COMMENT 'Indicates whether Digital Rights Management (DRM) encryption is applied to this channels content stream for OTT/streaming delivery. Drives content protection configuration in Akamai CDN and subscriber entitlement enforcement in Zuora.',
    `epg_enabled` BOOLEAN COMMENT 'Indicates whether this channel is published to the Electronic Program Guide (EPG) for audience-facing schedule display. Channels under testing or decommissioned may be excluded from EPG publication.',
    `hls_stream_url` STRING COMMENT 'The HLS (HTTP Live Streaming) manifest URL for this channels live stream, used for Apple device and browser-based OTT delivery via Akamai CDN. Supports ABR (Adaptive Bitrate Streaming) for adaptive quality delivery.',
    `launch_date` DATE COMMENT 'The date on which this channel first went live and began broadcasting. Used for channel lifecycle tracking, anniversary reporting, regulatory licence history, and audience growth analytics.',
    `logical_channel_number` STRING COMMENT 'The numeric channel position assigned to this channel in the Electronic Program Guide (EPG) and set-top box channel lineup. Used by MVPDs and vMVPDs for channel navigation and must-carry compliance reporting.',
    `max_ad_load_pct` DECIMAL(18,2) COMMENT 'Maximum percentage of total broadcast hour that may be allocated to advertising on this channel. Governs inventory capacity planning, FCC commercial limits compliance (childrens programming), and upfront/scatter market sales commitments.',
    `mediafirst_channel_code` STRING COMMENT 'The channel identifier as configured in the Ericsson MediaFirst playout automation system. Used to link this master channel record to the playout engine for schedule execution, automation triggers, graphics insertion, and failover configuration.',
    `mpeg_dash_stream_url` STRING COMMENT 'The MPEG-DASH (Dynamic Adaptive Streaming over HTTP) manifest URL for this channels live stream, used for Android, Smart TV, and cross-platform OTT delivery via Akamai CDN.',
    `must_carry_status` BOOLEAN COMMENT 'Indicates whether this channel is subject to must-carry obligations requiring MVPDs to include it in their channel lineup. Drives compliance reporting and carriage fee negotiations.',
    `network_name` STRING COMMENT 'Human-readable name of the broadcast network or channel brand (e.g., CNN, BBC One, ESPN). Used as the primary identity label for display in EPG, scheduling tools, and audience-facing interfaces.',
    `nielsen_station_code` STRING COMMENT 'The unique station identifier assigned by Nielsen Media Research for audience measurement, ratings reporting, and GRP/TRP calculations. Links this channel to Nielsen ratings data for advertising sales and audience analytics.',
    `playout_automation_enabled` BOOLEAN COMMENT 'Indicates whether the channel is configured for automated playout via Ericsson MediaFirst. When true, schedule execution, ad insertion cues, and failover are handled automatically. When false, manual playout operation is required.',
    `primary_language` STRING COMMENT 'ISO 639-1/639-2 language code representing the primary audio language of the channels programming (e.g., en for English, es for Spanish, fra for French). Used for EPG metadata, accessibility compliance, and audience targeting.. Valid values are `^[a-z]{2,3}$`',
    `retransmission_consent_required` BOOLEAN COMMENT 'Indicates whether this channel requires retransmission consent from MVPDs before rebroadcasting. Drives carriage fee negotiations and compliance with FCC retransmission consent rules.',
    `scte35_enabled` BOOLEAN COMMENT 'Indicates whether SCTE-35 digital program insertion cue markers are active on this channel for Dynamic Ad Insertion (DAI). SCTE-35 signals define ad pod boundaries and splice points used by Wide Orbit traffic system and DAI platforms.',
    `transmission_standard` STRING COMMENT 'Technical broadcast transmission standard used to deliver the channel signal. ATSC and ATSC 3.0 apply to North American over-the-air broadcast; DVB-T/T2 and DVB-S/S2 apply to European terrestrial and satellite; QAM applies to cable distribution; IP applies to OTT/streaming delivery. [ENUM-REF-CANDIDATE: ATSC|ATSC3|DVB-T|DVB-T2|DVB-S|DVB-S2|QAM|IP — promote to reference product]',
    `updated_timestamp` TIMESTAMP COMMENT 'The timestamp when this channel record was most recently modified. Used for change data capture (CDC), incremental ETL processing, and audit trail compliance in the Databricks Silver Layer.',
    `wide_orbit_station_code` STRING COMMENT 'The station code as configured in the Wide Orbit traffic and billing system. Used to link this channel master record to ad scheduling, sales orders, affidavit generation, and invoicing workflows in Wide Orbit.',
    CONSTRAINT pk_channel PRIMARY KEY(`channel_id`)
) COMMENT 'Master record for each linear broadcast channel — capturing network identity, call sign, transmission standard (ATSC, DVB-T/T2, QAM), logical channel number, language, resolution profile (SD/HD/UHD), and playout automation linkage to Ericsson MediaFirst. Serves as the SSOT for channel identity referenced by program schedules, EPG entries, playout events, and simulcast configurations within this domain.';

CREATE OR REPLACE TABLE `media_broadcasting_ecm`.`scheduling`.`daypart` (
    `daypart_id` BIGINT COMMENT 'Primary key for daypart',
    `dai_configuration_id` BIGINT COMMENT 'Foreign key linking to distribution.dai_configuration. Business justification: Daypart-specific DAI rules enforce regulatory and business constraints (COPPA restrictions in childrens dayparts, primetime ad load caps, scatter vs upfront eligibility). Technical operations configu',
    `demographic_segment_id` BIGINT COMMENT 'Foreign key linking to audience.demographic_segment. Business justification: Dayparts are defined by target demographic (target_demographic is a denormalized plain column). Linking daypart to demographic_segment enables proper GRP calculation, rate card pricing, and upfront pl',
    `genre_id` BIGINT COMMENT 'Foreign key linking to content.genre. Business justification: Dayparts have genre affinity rules (kids daypart restricts to childrens genre, news daypart to news/current affairs). Linking to content.genre enables automated scheduling constraint enforcement and ',
    `regulatory_obligation_id` BIGINT COMMENT 'Foreign key linking to compliance.regulatory_obligation. Business justification: Daypart restrictions (coppa_restricted, content_rating_restriction, safe harbor hours for indecency rules) are mandated by specific regulatory obligations. Compliance teams need to know which regulato',
    `revenue_stream_id` BIGINT COMMENT 'Foreign key linking to finance.revenue_stream. Business justification: Dayparts are the primary unit of advertising revenue planning and rate card management in broadcasting. Finance and sales plan revenue budgets by daypart × revenue stream (e.g., primetime advertising ',
    `ad_pod_max_count` STRING COMMENT 'The maximum number of ad pods (commercial breaks) permitted per hour within this daypart. Used by Wide Orbit for ad scheduling capacity planning and by Ericsson MediaFirst for playout rundown validation. Supports FCC commercial time compliance monitoring.',
    `ad_pod_max_duration_seconds` STRING COMMENT 'The maximum allowable total duration in seconds for an ad pod (group of ads in a break) within this daypart. Governs commercial break length limits enforced by Ericsson MediaFirst playout automation and Wide Orbit ad scheduling. Aligns with FCC commercial time limits for childrens programming dayparts.',
    `applicable_days` STRING COMMENT 'Pipe-delimited list of days of the week on which this daypart definition applies, using three-letter abbreviations (e.g., MON|TUE|WED|THU|FRI for weekday dayparts, SAT|SUN for weekend). Governs schedule generation in Ericsson MediaFirst and ad inventory availability in Wide Orbit. [ENUM-REF-CANDIDATE: MON|TUE|WED|THU|FRI|SAT|SUN — promote to reference product]',
    `avg_audience_000` DECIMAL(18,2) COMMENT 'The average audience size in thousands of viewers (000s) expected during this daypart, based on Nielsen Media Research Platform historical ratings data. Used as the principal quantitative measurement of daypart audience value for ad sales, GRP calculations, and content scheduling decisions.',
    `base_cpm_usd` DECIMAL(18,2) COMMENT 'The baseline CPM (Cost Per Mille) rate in US dollars for advertising inventory sold within this daypart, before application of the rate_multiplier or audience demographic adjustments. Represents the floor pricing reference used in Salesforce Media Cloud upfront and scatter market proposals.',
    `blackout_eligible` BOOLEAN COMMENT 'Indicates whether geographic broadcast blackout restrictions can be applied to content scheduled within this daypart. When True, blackout rules (e.g., sports rights geographic exclusivity) may be enforced by the distribution platform. Aligns with must-carry and retransmission consent obligations.',
    `content_rating_restriction` STRING COMMENT 'The maximum permissible TV content rating (per MPA/TV Parental Guidelines) for programming scheduled within this daypart. Enforces content appropriateness standards — e.g., Prime Time may allow up to TV-14, while Childrens dayparts are restricted to TV-Y or TV-Y7. Used by Ericsson MediaFirst for schedule validation.. Valid values are `TV-Y|TV-Y7|TV-G|TV-PG|TV-14|TV-MA`',
    `coppa_restricted` BOOLEAN COMMENT 'Indicates whether this daypart is subject to COPPA (Childrens Online Privacy Protection Act) restrictions due to programming directed at children under 13. When True, audience data collection, behavioral targeting, and ad pod duration limits are governed by COPPA compliance rules and FCC childrens television regulations.',
    `created_timestamp` TIMESTAMP COMMENT 'The timestamp when this daypart record was first created in the scheduling domain data product. Supports audit trail, data lineage tracking, and Silver layer ingestion reconciliation in the Databricks Lakehouse.',
    `dai_eligible` BOOLEAN COMMENT 'Indicates whether this daypart is eligible for Dynamic Ad Insertion (DAI) on OTT and streaming platforms. When True, ad pods within this daypart can be dynamically replaced with targeted ads during streaming delivery through Akamai CDN, enabling addressable advertising revenue.',
    `day_category` STRING COMMENT 'High-level classification of the day-of-week applicability for the daypart. weekday covers Monday–Friday, weekend covers Saturday–Sunday, all_week applies every day, and holiday applies on designated public holidays. Used for rate card segmentation and audience demographic profiling.. Valid values are `weekday|weekend|all_week|holiday`',
    `daypart_code` STRING COMMENT 'Short alphanumeric business identifier for the daypart, used as the externally-known reference key across Wide Orbit traffic system, Ericsson MediaFirst playout automation, and Salesforce Media Cloud ad sales. Examples: PRIME, EARLY_AM, DAYTIME, LATE_FRINGE, OVERNIGHT. Aligns with Nielsen daypart taxonomy codes.. Valid values are `^[A-Z0-9_]{2,20}$`',
    `daypart_description` STRING COMMENT 'Free-text narrative description of the daypart, including its programming characteristics, audience profile, and scheduling context. Used for internal documentation, Salesforce Media Cloud proposal narratives, and EPG metadata. Example: Prime Time (8PM-11PM) — highest-rated evening programming block targeting Adults 18-49.',
    `daypart_name` STRING COMMENT 'Human-readable label for the daypart segment as displayed in the Electronic Program Guide (EPG), ad sales proposals, and scheduling interfaces. Examples: Early Morning, Morning Drive, Daytime, Prime Time, Late Fringe, Overnight.',
    `daypart_status` STRING COMMENT 'Current lifecycle state of the daypart definition. active indicates the daypart is in operational use for scheduling and ad sales. inactive means temporarily suspended. draft means under review before activation. deprecated means retired from use but retained for historical reference.. Valid values are `active|inactive|draft|deprecated`',
    `daypart_type` STRING COMMENT 'Classifies the daypart by broadcast delivery mode. linear applies to traditional scheduled broadcast, non_linear to on-demand programming windows, simulcast to simultaneous multi-platform broadcast segments, and vod_window to VOD availability windows governed by this daypart definition.. Valid values are `linear|non_linear|simulcast|vod_window`',
    `duration_minutes` STRING COMMENT 'Total duration of the daypart window expressed in minutes. Derived from start_time and end_time boundaries but stored explicitly for scheduling calculations, ad inventory capacity planning, and rate card generation in Wide Orbit.',
    `effective_from` DATE COMMENT 'The calendar date from which this daypart definition becomes effective for scheduling and ad sales operations. Supports versioned daypart definitions where boundaries or rates change seasonally or following regulatory updates. Used in Wide Orbit and Ericsson MediaFirst schedule generation.',
    `effective_until` DATE COMMENT 'The calendar date on which this daypart definition expires and is no longer applicable for scheduling and ad sales. Null indicates an open-ended definition with no planned expiry. Supports seasonal daypart adjustments (e.g., summer schedule changes) and regulatory compliance updates.',
    `end_time` TIMESTAMP COMMENT 'The clock time (HH:mm:ss, 24-hour or extended broadcast-day format) at which the daypart ends. Supports broadcast day overflow notation (e.g., 25:59:59 for content airing past midnight within the same broadcast day). Paired with start_time to define the daypart boundary.',
    `epg_display_order` STRING COMMENT 'The sequential display order of this daypart within the Electronic Program Guide (EPG) channel grid, used by Ericsson MediaFirst for schedule presentation and by digital EPG distribution systems. Lower values appear earlier in the broadcast day display.',
    `grp_index` DECIMAL(18,2) COMMENT 'The GRP (Gross Rating Point) index value representing the expected audience delivery weight for this daypart relative to the total broadcast day. Used in media planning, upfront negotiations, and scatter market pricing. Sourced from Nielsen Media Research Platform ratings data.',
    `hut_level` DECIMAL(18,2) COMMENT 'The HUT (Homes Using Television) percentage representing the proportion of TV households actively viewing during this daypart. A key audience measurement metric sourced from Nielsen Media Research Platform, used to benchmark daypart audience potential and inform ad pricing.',
    `makegood_eligible` BOOLEAN COMMENT 'Indicates whether compensatory ad spots (makegoods) can be scheduled within this daypart to fulfill underdelivered audience guarantees from other dayparts. Governs Wide Orbit makegood scheduling logic and Salesforce Media Cloud campaign reconciliation workflows.',
    `nielsen_daypart_code` STRING COMMENT 'The standardized daypart code as defined by Nielsen Media Research taxonomy (e.g., PRIME, EARLY_NEWS, LATE_NEWS, DAYTIME, EARLY_FRINGE, LATE_FRINGE, OVERNIGHT). Used to align internal scheduling definitions with Nielsen audience measurement reports and ratings data ingested from the Nielsen Media Research Platform.',
    `rate_multiplier` DECIMAL(18,2) COMMENT 'Pricing multiplier applied to the base CPM (Cost Per Mille) rate card for ad inventory sold within this daypart. A value of 1.0000 represents the base rate; Prime Time typically carries a multiplier greater than 1.0 (e.g., 2.5000), while Overnight may be below 1.0 (e.g., 0.3000). Used in Salesforce Media Cloud proposal generation and Wide Orbit billing.',
    `scatter_eligible` BOOLEAN COMMENT 'Indicates whether unsold ad inventory within this daypart is available for scatter market (last-minute) sales. Governs Wide Orbit inventory availability rules for short-notice ad placement and makegood scheduling.',
    `scte35_cue_enabled` BOOLEAN COMMENT 'Indicates whether SCTE-35 digital program insertion cue markers are enabled for ad break signaling within this daypart. When True, Ericsson MediaFirst playout automation inserts SCTE-35 splice_insert commands at ad pod boundaries, enabling Dynamic Ad Insertion (DAI) for OTT and streaming distribution via Akamai CDN.',
    `simulcast_eligible` BOOLEAN COMMENT 'Indicates whether content scheduled in this daypart is eligible for simultaneous multi-platform broadcast (simulcast) across linear, OTT, and digital channels. When True, Ericsson MediaFirst can trigger simulcast distribution workflows for this dayparts programming.',
    `start_time` TIMESTAMP COMMENT 'The clock time (HH:mm:ss, 24-hour format) at which the daypart begins each applicable day. Used by Ericsson MediaFirst for automated playout boundary detection and by Wide Orbit for ad scheduling slot assignment. Stored as STRING to support broadcast day conventions (e.g., 25:00:00 for post-midnight).',
    `sweeps_period_flag` BOOLEAN COMMENT 'Indicates whether this daypart definition has special audience measurement and programming rules applied during Nielsen sweeps periods (intensive ratings measurement periods in February, May, July, and November). When True, enhanced content scheduling and ad pricing rules may apply.',
    `timezone_code` STRING COMMENT 'The IANA timezone identifier (e.g., America/New_York, America/Los_Angeles, Europe/London) governing the clock boundaries of this daypart. Critical for multi-market broadcast operations where the same daypart definition must be applied across different time zones for network affiliates and regional channels.. Valid values are `^[A-Za-z_/]{3,40}$`',
    `updated_timestamp` TIMESTAMP COMMENT 'The timestamp of the most recent modification to this daypart record. Used for change data capture (CDC), incremental ETL processing in the Databricks Lakehouse Silver layer, and audit trail compliance.',
    `upfront_eligible` BOOLEAN COMMENT 'Indicates whether ad inventory within this daypart is offered during the upfront advance advertising sales event. Prime Time and key dayparts are typically upfront-eligible. Drives Salesforce Media Cloud opportunity and proposal configuration for annual upfront sales cycles.',
    `wide_orbit_daypart_code` STRING COMMENT 'The corresponding daypart identifier as configured in the Wide Orbit traffic and billing system. Used to reconcile internal daypart definitions with ad scheduling, sales orders, and affidavit records in Wide Orbit. Enables cross-system traceability for revenue assurance.',
    CONSTRAINT pk_daypart PRIMARY KEY(`daypart_id`)
) COMMENT 'Reference definition of named broadcast time segments (e.g., Early Morning, Morning Drive, Daytime, Prime Time, Late Fringe, Overnight) used to govern ad pricing, content scheduling, and audience targeting. Captures daypart code, start/end time boundaries, day-of-week applicability, audience demographic profile, and rate multiplier. Aligns with Nielsen daypart taxonomy and Wide Orbit traffic system.';

CREATE OR REPLACE TABLE `media_broadcasting_ecm`.`scheduling`.`program_schedule` (
    `program_schedule_id` BIGINT COMMENT 'Unique surrogate identifier for the program schedule record. One record per channel per broadcast date per schedule version. This is the primary key of the program_schedule data product.',
    `acquisition_deal_id` BIGINT COMMENT 'Foreign key linking to partner.acquisition_deal. Business justification: Program schedules airing acquired content must reference the acquisition deal for rights clearance verification, holdback compliance, and run-allowance tracking. Rights management and traffic operatio',
    `affiliate_agreement_id` BIGINT COMMENT 'Foreign key linking to partner.affiliate_agreement. Business justification: Affiliate station program schedules must reference the affiliate agreement to track must-air programming hours, preemption rights, and network compensation calculations. Affiliate relations and networ',
    `asset_collection_id` BIGINT COMMENT 'Foreign key linking to mediaasset.asset_collection. Business justification: Syndication and themed programming blocks (e.g., a sports package, holiday marathon) are built from pre-curated asset collections. Scheduling teams assign a collection to a program schedule block, ena',
    `broadcast_license_id` BIGINT COMMENT 'Foreign key linking to compliance.broadcast_license. Business justification: Program schedules must comply with license terms including childrens programming quotas, must-carry requirements, and public interest obligations. Required for FCC quarterly compliance reports and li',
    `channel_id` BIGINT COMMENT 'Reference to the broadcast channel for which this schedule is defined. Identifies the linear channel in the channel master (e.g., NBC East, CNN HD). Drives Ericsson MediaFirst playout automation for the specific channel.',
    `coproduction_agreement_id` BIGINT COMMENT 'Foreign key linking to partner.coproduction_agreement. Business justification: Program schedules airing co-produced content must reference the co-production agreement for credit obligation display, distribution rights allocation verification, and residuals tracking. Co-productio',
    `cost_center_id` BIGINT COMMENT 'Foreign key linking to finance.cost_center. Business justification: Program schedules incur production and transmission costs tracked to cost centers. Schedule cost reconciliation, budget variance analysis, and production accounting require this mapping. Standard broa',
    `delivery_channel_id` BIGINT COMMENT 'Foreign key linking to distribution.delivery_channel. Business justification: Program schedules are published to specific delivery channels (linear, OTT, FAST). EPG syndication, rights enforcement, and ad insertion configuration all require knowing which delivery channel a sche',
    `distribution_agreement_id` BIGINT COMMENT 'Foreign key linking to partner.distribution_agreement. Business justification: Program schedules distributed to MVPDs or affiliates must reference the governing distribution agreement for must-carry compliance verification, blackout restriction enforcement, and carriage obligati',
    `license_agreement_id` BIGINT COMMENT 'Foreign key linking to rights.license_agreement. Business justification: Schedule approval workflows require confirming the license agreement is valid for the scheduled broadcast period, territory, and channel. Rights clearance status on program_schedule is meaningless wit',
    `market_coverage_id` BIGINT COMMENT 'Foreign key linking to audience.market_coverage. Business justification: Program schedules are market-specific — must-carry compliance, blackout rules, and retransmission consent obligations vary by DMA. Linking program_schedule to market_coverage enables market-level comp',
    `ott_platform_id` BIGINT COMMENT 'Foreign key linking to distribution.ott_platform. Business justification: Program schedules are published to OTT platforms for live streaming and on-demand availability. Platform-specific scheduling (staggered release, platform exclusives, EPG publishing) requires this link',
    `production_budget_id` BIGINT COMMENT 'Foreign key linking to finance.production_budget. Business justification: Program schedules are executed against approved production budgets; finance controllers reconcile scheduled programming costs against budget lines for variance reporting and period-close. A media-broa',
    `regulatory_obligation_id` BIGINT COMMENT 'Foreign key linking to compliance.regulatory_obligation. Business justification: Program schedules must satisfy named regulatory obligations — FCC 3-hour childrens programming rule, political broadcasting equal-time requirements, EAS compliance windows. The fcc_children_programmi',
    `syndication_agreement_id` BIGINT COMMENT 'Foreign key linking to partner.syndication_agreement. Business justification: Program schedules carrying syndicated content must reference the governing syndication agreement for rights clearance status, run-count tracking, barter spot reconciliation, and clearance obligation v',
    `ad_pod_count` STRING COMMENT 'Total number of ad pods (groups of ads in a break) planned in the schedule for this channel day. An ad pod is a contiguous block of commercial spots within a program break. Used for inventory planning and SCTE-35 cue marker validation.',
    `approved_by` STRING COMMENT 'Name or user identifier of the programming operations staff member who approved this schedule version. Required for audit trail and accountability in the schedule approval workflow. Populated when schedule_status transitions to approved.',
    `approved_timestamp` TIMESTAMP COMMENT 'Timestamp when this schedule version was formally approved by the programming team. Marks the transition from draft to approved status. Used for SLA tracking of schedule readiness lead time before broadcast date.',
    `as_run_confirmed_timestamp` TIMESTAMP COMMENT 'Timestamp when the as-run log was confirmed and reconciled against the planned schedule. Marks the transition to as-run status. Used for Wide Orbit affidavit generation, Nielsen ratings reconciliation, and revenue assurance.',
    `blackout_flag` BOOLEAN COMMENT 'Indicates whether any geographic broadcast blackout restriction applies to this schedule. True = one or more programs in this schedule are subject to blackout in specific markets (e.g., sports rights blackout). Triggers downstream blackout enforcement in distribution and CDN systems.',
    `broadcast_date` DATE COMMENT 'The calendar date for which this program schedule is planned and transmitted. Represents the broadcast day (which may span midnight for overnight programming). Formatted as yyyy-MM-dd per enterprise date convention.',
    `broadcast_standard` STRING COMMENT 'The broadcast technical standard under which this schedule is transmitted. ATSC = Advanced Television Systems Committee (North America); DVB = Digital Video Broadcasting (Europe/international); ISDB = Integrated Services Digital Broadcasting (Japan/Brazil); NTSC/PAL = legacy analog standards.. Valid values are `ATSC|DVB|ISDB|NTSC|PAL`',
    `content_rating_advisory` STRING COMMENT 'The highest content rating advisory applicable to any program in this schedule for the broadcast day. Used for parental control systems, V-chip compliance, and FCC content standards reporting. Ratings follow the TV Parental Guidelines system mandated by the FCC.. Valid values are `TV-Y|TV-Y7|TV-G|TV-PG|TV-14|TV-MA`',
    `created_timestamp` TIMESTAMP COMMENT 'Timestamp when this program schedule record was first created in the system. Represents the business event time of schedule initiation. Used for audit trail, SLA measurement of schedule build lead time, and data lineage tracking.',
    `dalet_workflow_code` STRING COMMENT 'Reference identifier for the Dalet Galaxy media asset management workflow instance associated with this schedules content preparation and ingest activities. Links the schedule to the MAM workflow for asset readiness validation prior to playout.',
    `daypart_code` STRING COMMENT 'Primary daypart classification for the schedules dominant programming block. Daypart is the time segment of the broadcast day used for audience measurement, ad sales, and programming strategy. Values align with Nielsen daypart definitions. [ENUM-REF-CANDIDATE: EARLY_MORNING|MORNING|DAYTIME|EARLY_FRINGE|PRIME_ACCESS|PRIME|LATE_NEWS|LATE_FRINGE|OVERNIGHT — promote to reference product]',
    `emergency_alert_ready` BOOLEAN COMMENT 'Indicates whether the schedule has been configured with Emergency Alert System (EAS) interrupt capability for this broadcast date. True = EAS interrupt slots are provisioned in the Ericsson MediaFirst rundown. Required for FCC EAS compliance.',
    `epg_grid_code` STRING COMMENT 'External identifier assigned to this schedule in the Electronic Program Guide (EPG) distribution system. Used by downstream EPG aggregators, set-top box providers, and digital guide services to reference the channel day grid. Aligns with DVB SI/EIT table identifiers.',
    `fcc_children_programming_compliant` BOOLEAN COMMENT 'Indicates whether this schedule meets FCC childrens educational and informational (E/I) programming requirements for the broadcast date. True = minimum required hours of qualifying childrens programming are scheduled. Required for FCC license renewal compliance reporting.',
    `last_modified_timestamp` TIMESTAMP COMMENT 'Timestamp of the most recent modification to this program schedule record. Tracks the last update across any field change, version increment, or status transition. Used for change detection in downstream EPG distribution and playout systems.',
    `mediafirst_rundown_code` STRING COMMENT 'Reference identifier for the automation rundown object in Ericsson MediaFirst that corresponds to this program schedule. Used to reconcile the planned schedule with the playout automation systems rundown for failover and as-run log generation.',
    `must_carry_compliant` BOOLEAN COMMENT 'Indicates whether this schedule satisfies must-carry obligations for the channel on this broadcast date. Must-carry is the mandatory channel inclusion requirement imposed on cable and satellite MVPDs by the FCC. True = compliant; False = compliance issue requiring resolution.',
    `playout_failover_mode` STRING COMMENT 'Indicates the Ericsson MediaFirst playout failover configuration active for this schedule. primary = normal automated playout; backup = failover to backup playout server; manual_override = operator has taken manual control of playout. Used for SLA and incident reporting.. Valid values are `primary|backup|manual_override`',
    `rights_clearance_status` STRING COMMENT 'Aggregate rights clearance status for all programs in this schedule as verified against Rightsline rights management. cleared = all programs have confirmed broadcast rights for this date and territory; pending = clearance in progress; partial = some programs cleared; failed = one or more rights conflicts identified.. Valid values are `cleared|pending|partial|failed`',
    `schedule_end_time` TIMESTAMP COMMENT 'The planned end timestamp of the broadcast schedule for this channel day, including timezone offset. Typically 23:59:59 local broadcast time but may extend past midnight for overnight programming blocks. Formatted as yyyy-MM-ddTHH:mm:ss.SSSXXX.',
    `schedule_name` STRING COMMENT 'Human-readable label for the schedule, typically combining channel name and broadcast date (e.g., CNN-HD 2024-06-15 v2). Used by scheduling operations staff to identify and reference the schedule in Ericsson MediaFirst and Wide Orbit Traffic systems.',
    `schedule_notes` STRING COMMENT 'Free-text operational notes entered by scheduling staff regarding special instructions, exceptions, or context for this schedule (e.g., Breaking news override applied to 8PM slot, Live sports event extends prime block by 30 min). Not used for automated processing.',
    `schedule_source` STRING COMMENT 'Indicates how this schedule was generated. manual = built by scheduling staff; automated = generated by Ericsson MediaFirst automated schedule engine; imported = ingested from an external programming supplier or network feed; template = derived from a recurring schedule template.. Valid values are `manual|automated|imported|template`',
    `schedule_start_time` TIMESTAMP COMMENT 'The planned start timestamp of the broadcast schedule for this channel day, including timezone offset. Typically 00:00:00 local broadcast time but may differ for overnight schedules that begin at a non-midnight boundary. Formatted as yyyy-MM-ddTHH:mm:ss.SSSXXX.',
    `schedule_status` STRING COMMENT 'Current lifecycle state of the program schedule. draft = initial build in progress; approved = signed off by programming team; transmitted = sent to Ericsson MediaFirst playout automation; as-run = actual broadcast log confirmed; cancelled = schedule voided and replaced.. Valid values are `draft|approved|transmitted|as-run|cancelled`',
    `schedule_type` STRING COMMENT 'Classification of the schedule by programming strategy type. standard = regular broadcast day; special_event = live event or breaking news override; holiday = holiday programming grid; sweeps = Nielsen sweeps period intensive ratings schedule; upfront_preview = advance advertising sales event programming.. Valid values are `standard|special_event|holiday|sweeps|upfront_preview`',
    `schedule_version` STRING COMMENT 'Monotonically incrementing version number for the schedule on a given channel and broadcast date. Enables tracking of schedule revisions from initial draft through final as-run. Version 1 is the initial draft; each approved revision increments the version.',
    `scte35_cue_count` STRING COMMENT 'Total number of SCTE-35 digital program insertion cue markers embedded in the schedule for this channel day. SCTE-35 cues signal ad break opportunities for Dynamic Ad Insertion (DAI) in both linear and OTT streams. Used to validate DAI readiness.',
    `simulcast_flag` BOOLEAN COMMENT 'Indicates whether this schedule is configured for simultaneous multi-platform broadcast (simulcast). True = the schedule is transmitted concurrently across linear broadcast and one or more OTT/streaming platforms. Drives Ericsson MediaFirst simulcast automation configuration.',
    `simulcast_platform_count` STRING COMMENT 'Number of platforms on which this schedule is simultaneously broadcast when simulcast_flag is True. Used for multi-platform distribution planning and rights compliance verification across linear, OTT, and vMVPD delivery channels.',
    `timezone` STRING COMMENT 'IANA timezone identifier for the broadcast timezone in which this schedules times are expressed (e.g., America/New_York, Europe/London). Critical for accurate EPG display, daypart classification, and regulatory compliance reporting across markets.',
    `total_ad_time_seconds` STRING COMMENT 'Total planned advertising airtime in seconds across all ad pods in the schedule for this channel day. Used for commercial inventory management, FCC commercial limits compliance, and revenue forecasting against Wide Orbit traffic orders.',
    `total_program_time_seconds` STRING COMMENT 'Total planned programming (non-commercial) airtime in seconds for this channel day schedule. Equals total_runtime_seconds minus total_ad_time_seconds. Used for content utilization reporting and rights compliance verification.',
    `total_runtime_seconds` STRING COMMENT 'Total planned runtime of all program items in the schedule, expressed in seconds. Used to validate that the schedule fills the full broadcast day (86,400 seconds for a 24-hour schedule) and to detect gaps or overlaps in the rundown.',
    `transmission_type` STRING COMMENT 'Indicates the primary mode of content delivery for this schedule. linear = traditional scheduled broadcast; vod_window = on-demand programming window; fast_channel = Free Ad-Supported Streaming Television (FAST) channel; simulcast = simultaneous multi-platform broadcast.. Valid values are `linear|vod_window|fast_channel|simulcast`',
    `transmitted_timestamp` TIMESTAMP COMMENT 'Timestamp when the approved schedule was transmitted to the Ericsson MediaFirst playout automation system. Marks the transition from approved to transmitted status. Used for playout readiness SLA monitoring and failover preparation.',
    `wide_orbit_log_code` STRING COMMENT 'Reference identifier for the corresponding traffic log in Wide Orbit Traffic and Billing system. Links the program schedule to the ad scheduling and affidavit records for commercial break reconciliation and proof-of-broadcast (affidavit) generation.',
    CONSTRAINT pk_program_schedule PRIMARY KEY(`program_schedule_id`)
) COMMENT 'The authoritative linear channel grid (EPG backbone) representing the planned broadcast schedule for a channel on a given broadcast date. Captures schedule version, channel, broadcast date, schedule status (draft, approved, transmitted, as-run), total runtime, blackout flags, must-carry compliance status, and the Ericsson MediaFirst automation rundown reference. One record per channel per broadcast day per schedule version.';

CREATE OR REPLACE TABLE `media_broadcasting_ecm`.`scheduling`.`schedule_slot` (
    `schedule_slot_id` BIGINT COMMENT 'Unique surrogate identifier for each individual schedule slot record within the Electronic Program Guide (EPG) rundown. Primary key for the schedule_slot data product managed in Ericsson MediaFirst.',
    `acquisition_deal_id` BIGINT COMMENT 'Foreign key linking to partner.acquisition_deal. Business justification: Schedule slots airing acquired content must reference the acquisition deal for holdback enforcement, run-allowance verification, and royalty calculation per airing. Rights clearance workflows in broad',
    `affiliate_agreement_id` BIGINT COMMENT 'Foreign key linking to partner.affiliate_agreement. Business justification: Schedule slots on affiliate stations must reference the affiliate agreement to enforce local ad avail minute allocation, preemption rights, and simulcast requirements at the slot level. Affiliate traf',
    `asset_version_id` BIGINT COMMENT 'Foreign key linking to mediaasset.asset_version. Business justification: Pre-air QC gate and playout automation require knowing the EXACT asset version (codec, resolution, DRM) cleared for a slot — not just the master asset. Traffic and automation systems validate format c',
    `channel_id` BIGINT COMMENT 'Reference to the linear broadcast channel on which this schedule slot is programmed. Identifies the originating channel within the EPG grid.',
    `content_rating_id` BIGINT COMMENT 'Foreign key linking to compliance.content_rating. Business justification: Each scheduled slot requires verified content rating for daypart appropriateness (watershed compliance), V-chip encoding, and parental guidance systems. Real-time compliance verification prevents regu',
    `content_episode_id` BIGINT COMMENT 'Foreign key linking to content.content_episode. Business justification: For episodic programming, schedulers link slots to specific episodes for episode sequencing, repeat/rerun tracking (rerun_flag exists on schedule_slot), and EPG accuracy. Episode-level slot assignment',
    `contract_id` BIGINT COMMENT 'Foreign key linking to talent.contract. Business justification: Traffic and rights clearance teams must verify that a valid talent contract covers the usage rights, territory, and exclusivity terms for each scheduled slot before broadcast. This contract-per-slot v',
    `daypart_id` BIGINT COMMENT 'Reference to the daypart classification assigned to this slot (e.g., Prime Time, Late Night, Morning Drive). Dayparts are standard time segments of the broadcast day used for audience targeting and advertising rate-card pricing.',
    `delivery_channel_id` BIGINT COMMENT 'Foreign key linking to distribution.delivery_channel. Business justification: Individual schedule slots are delivered via specific delivery channels, driving DAI targeting, blackout enforcement, and QoS monitoring per slot. Ad operations and traffic systems require slot-level d',
    `distribution_agreement_id` BIGINT COMMENT 'Foreign key linking to partner.distribution_agreement. Business justification: Schedule slots on distributed channels must reference the distribution agreement for slot-level blackout restriction enforcement and must-carry compliance verification. Distribution operations require',
    `drm_policy_id` BIGINT COMMENT 'Foreign key linking to distribution.drm_policy. Business justification: Schedule slots for streaming/OTT delivery require a DRM policy assignment for rights enforcement and geo-restriction. Content protection compliance reporting and automated DRM enforcement during sched',
    `grant_id` BIGINT COMMENT 'Foreign key linking to rights.grant. Business justification: Royalty calculation and rights exploitation reporting require knowing which specific grant (right type, territory, media type) authorizes each scheduled slot. Grants determine royalty rates and residu',
    `media_asset_id` BIGINT COMMENT 'Foreign key linking to mediaasset.media_asset. Business justification: Schedule slots must reference the specific media file for playout automation systems (MediaFirst, WideOrbit) to execute. Critical for broadcast operations - automation pulls the actual file URI from t',
    `program_schedule_id` BIGINT COMMENT 'Reference to the parent broadcast schedule or rundown document that contains this slot. Links the atomic slot to its daily or weekly schedule container in Ericsson MediaFirst.',
    `revenue_stream_id` BIGINT COMMENT 'Foreign key linking to finance.revenue_stream. Business justification: Schedule slots generate revenue through ad sales, sponsorships, and carriage fees. ASC 606 revenue recognition, sales order fulfillment, and revenue assurance all require slot-to-revenue-stream mappin',
    `scheduling_availability_window_id` BIGINT COMMENT 'Reference to the active rights window in Rightsline that authorizes the broadcast of the content in this slot. Validates that the airing falls within the licensed holdback and windowing period for the territory and platform.',
    `syndication_agreement_id` BIGINT COMMENT 'Foreign key linking to partner.syndication_agreement. Business justification: Individual schedule slots carrying syndicated content must reference the syndication agreement to enforce run limits, territory restrictions, and barter spot allocation at the slot level. Syndication ',
    `talent_profile_id` BIGINT COMMENT 'Foreign key linking to talent.talent_profile. Business justification: On-air talent (hosts, anchors, guests) are scheduled in broadcast slots. Scheduling systems track which talent appears in which slot for call sheets, union reporting, rights clearance verification, an',
    `title_id` BIGINT COMMENT 'Reference to the content asset or media item assigned to this slot. Links to the Digital Asset Management (DAM) record in Dalet Galaxy for the program, promo, commercial, or filler material.',
    `holdback_id` BIGINT COMMENT 'Foreign key linking to rights.holdback. Business justification: Blackout enforcement on schedule slots is driven by holdback records. Linking slot to the triggering holdback enables blackout dispute resolution, holdback compliance reporting, and automated enforcem',
    `version_id` BIGINT COMMENT 'Foreign key linking to content.version. Business justification: Scheduling a specific version (dubbed, HD, SDR edit) is a core broadcast traffic operation. Traffic systems must record which version is scheduled per slot for playout automation handoff, rights compl',
    `actual_duration_seconds` STRING COMMENT 'Real-world duration of the slot in seconds as recorded in the as-run log. Compared against planned_duration_seconds to identify overruns, underruns, and schedule compliance deviations. Used in affidavit reconciliation and makegoods processing.',
    `actual_start_time` TIMESTAMP COMMENT 'Real-world start time of the slot as recorded in the as-run log by Ericsson MediaFirst playout automation. May differ from planned_start_time due to live events, technical delays, or schedule overruns. Critical for affidavit generation in Wide Orbit and Nielsen audience measurement reconciliation.',
    `aspect_ratio` STRING COMMENT 'Video aspect ratio of the content assigned to this slot. Drives playout automation letterboxing/pillarboxing decisions in Ericsson MediaFirst and ensures compliance with broadcast technical standards.. Valid values are `16:9|4:3|21:9|1:1`',
    `audio_format` STRING COMMENT 'Audio encoding format for the content in this slot (e.g., stereo, Dolby 5.1, Dolby Atmos, mono). Required for playout automation configuration in Ericsson MediaFirst and compliance with broadcast audio loudness standards.. Valid values are `stereo|dolby_5_1|dolby_atmos|mono|surround`',
    `automation_event_code` STRING COMMENT 'Ericsson MediaFirst playout automation system event identifier for this slot. The native key from the MediaFirst rundown used for as-run reconciliation, failover event tracking, and technical operations audit.',
    `broadcast_date` DATE COMMENT 'Calendar date on which this slot is scheduled to air, expressed in yyyy-MM-dd format. Used as the primary partition key for EPG queries, Nielsen ratings alignment, and daily schedule reporting. Represents the broadcast day which may span midnight for overnight programming.',
    `closed_caption_flag` BOOLEAN COMMENT 'Indicates whether closed captioning is present and enabled for this slot (True). Mandatory for FCC compliance under the Twenty-First Century Communications and Video Accessibility Act (CVAA) for applicable programming.',
    `created_timestamp` TIMESTAMP COMMENT 'Timestamp when this schedule slot record was first created in the EPG system. Supports audit trail requirements, schedule change history analysis, and data lineage tracking in the Databricks Silver Layer.',
    `eas_alert_type` STRING COMMENT 'Type of Emergency Alert System (EAS) message associated with this slot when slot_type is eas (e.g., EAN — Emergency Action Notification, NPT — National Periodic Test, RWT — Required Weekly Test). Null for non-EAS slots. Mandatory for FCC EAS compliance logging. [ENUM-REF-CANDIDATE: EAN|NPT|RWT|SVR|TOR|FFW|HUW|WSW — promote to reference product]',
    `episode_number` STRING COMMENT 'Episode identifier for serialized program content in this slot (e.g., S02E05 for Season 2, Episode 5). Used for rights window tracking in Rightsline, repeat detection, and EPG metadata publication.',
    `is_blackout` BOOLEAN COMMENT 'Indicates whether a geographic broadcast restriction (blackout) applies to this slot (True). Blackout rules are enforced at the distribution layer and must be flagged at the slot level for rights compliance and audience measurement exclusion.',
    `is_live` BOOLEAN COMMENT 'Indicates whether this slot carries a live broadcast event (True) or pre-recorded/taped content (False). Live slots require different playout automation handling, DAI configuration, and rights clearance verification in Rightsline.',
    `is_repeat` BOOLEAN COMMENT 'Indicates whether this slot is a repeat airing of previously broadcast content (True) rather than a first-run premiere (False). Affects talent residuals calculations in Rightsline and Nielsen audience measurement weighting.',
    `is_simulcast` BOOLEAN COMMENT 'Indicates whether this slot is simultaneously broadcast across multiple platforms or channels (True). Simulcast slots require coordinated playout across linear and OTT/streaming distribution paths and may trigger additional rights obligations.',
    `isan_code` STRING COMMENT 'International Standard Audiovisual Number (ISAN) uniquely identifying the audiovisual work airing in this slot. Enables cross-platform content identification, rights clearance verification in Rightsline, and royalty calculation for residuals.. Valid values are `^ISAN [0-9A-F]{4}-[0-9A-F]{4}-[0-9A-F]{4}-[0-9A-F]{4}-[0-9A-F]{1}-[0-9A-F]{4}-[0-9A-F]{4}-[0-9A-F]{1}$`',
    `isci_code` STRING COMMENT 'Industry Standard Commercial Identification (ISCI) code for the commercial spot airing in this slot. An 8-character alphanumeric code used by Wide Orbit and ad agencies to uniquely identify a specific commercial creative. Null for non-commercial slot types.. Valid values are `^[A-Z0-9]{8}$`',
    `must_carry_flag` BOOLEAN COMMENT 'Indicates whether this slot is subject to must-carry obligations requiring MVPDs to include this channel/content in their basic tier (True). Flags slots that cannot be blacked out or substituted under FCC must-carry rules.',
    `nielsen_program_code` STRING COMMENT 'Nielsen Media Research proprietary program code assigned to the content in this slot. Used to match as-run schedule data with Nielsen ratings data for audience measurement, GRP/TRP calculation, and advertiser reporting.',
    `planned_duration_seconds` STRING COMMENT 'Intended duration of the slot in seconds as scheduled in the EPG rundown. Used for schedule integrity validation, ad pod capacity planning, and compliance with broadcast standards for minimum program duration.',
    `planned_end_time` TIMESTAMP COMMENT 'Scheduled end date and time for this slot as defined in the EPG rundown. Derived from planned_start_time plus planned_duration_seconds but stored explicitly to support EPG grid queries and boundary validation.',
    `planned_start_time` TIMESTAMP COMMENT 'Scheduled start date and time for this slot as defined in the EPG rundown prior to broadcast. Expressed in ISO 8601 format with timezone offset. Used for EPG publication, audience measurement alignment, and ad trafficking in Wide Orbit.',
    `program_title` STRING COMMENT 'Human-readable title of the program or content event airing in this slot as it appears in the published EPG. Used for audience-facing program guides, Nielsen ratings matching, and schedule reporting.',
    `resolution` STRING COMMENT 'Video resolution classification of the content in this slot (SD, HD, UHD, 4K). Determines the playout chain and CDN delivery profile used by Akamai and affects carriage fee agreements with MVPDs.. Valid values are `SD|HD|UHD|4K`',
    `schedule_version` STRING COMMENT 'Version number of the schedule rundown in which this slot was last modified. Incremented each time the EPG rundown is revised in Ericsson MediaFirst. Supports schedule change audit trails and version comparison for compliance reporting.',
    `scte35_cue_in_time` TIMESTAMP COMMENT 'Timestamp of the SCTE-35 splice_insert cue-in signal marking the return to primary program content after an ad break. Paired with scte35_cue_out_time to define the exact ad avail window for DAI and Wide Orbit ad scheduling.',
    `scte35_cue_out_time` TIMESTAMP COMMENT 'Timestamp of the SCTE-35 splice_insert cue-out signal marking the start of an ad break or content interruption within this slot. Used by Dynamic Ad Insertion (DAI) systems and downstream distribution platforms to trigger ad replacement. Null for non-break slot types.',
    `slot_sequence_number` STRING COMMENT 'Ordinal position of this slot within the daily rundown for the channel. Determines the playout order in Ericsson MediaFirst automation. Sequence numbers are contiguous integers starting at 1 for each broadcast day.',
    `slot_status` STRING COMMENT 'Current lifecycle state of the schedule slot within the EPG workflow. Values: scheduled (initial EPG entry), confirmed (locked for playout), on_air (currently broadcasting), completed (as-run recorded), cancelled (removed from schedule), replaced (substituted with alternate content). Drives Ericsson MediaFirst automation state machine.. Valid values are `scheduled|confirmed|on_air|completed|cancelled|replaced`',
    `slot_type` STRING COMMENT 'Classification of the schedule slot by content category. Values: program (primary editorial content), promo (promotional spot), commercial_break (paid advertising break), filler (interstitial padding content), psa (Public Service Announcement), eas (Emergency Alert System message). Drives playout automation logic and ad insertion rules in Ericsson MediaFirst.. Valid values are `program|promo|commercial_break|filler|psa|eas`',
    `traffic_order_number` STRING COMMENT 'Wide Orbit traffic system order number associated with this slot when it carries a commercial or promotional spot. Links the EPG slot to the ad sales order for affidavit generation, billing reconciliation, and makegood processing.',
    `updated_timestamp` TIMESTAMP COMMENT 'Timestamp when this schedule slot record was last modified. Tracks EPG edits, schedule revisions, and as-run updates. Used in conjunction with schedule_version for change management and compliance audit.',
    CONSTRAINT pk_schedule_slot PRIMARY KEY(`schedule_slot_id`)
) COMMENT 'Individual time slot within a program schedule representing a single content event or break event on a linear channel. Captures slot sequence number, planned start time, planned duration, actual start time (as-run), actual duration, slot type (program, promo, commercial break, filler, PSA, EAS), content reference, daypart assignment, and live/tape flag. The atomic unit of the EPG rundown managed in Ericsson MediaFirst.';

CREATE OR REPLACE TABLE `media_broadcasting_ecm`.`scheduling`.`epg_entry` (
    `epg_entry_id` BIGINT COMMENT 'Unique surrogate identifier for each Electronic Program Guide (EPG) entry record in the scheduling domain. Serves as the primary key for this Silver Layer data product.',
    `asset_version_id` BIGINT COMMENT 'Foreign key linking to mediaasset.asset_version. Business justification: EPG feeds published to guide aggregators (Gracenote, TiVo, Apple TV) must include version-specific metadata — HDR flag, resolution, language tracks, subtitle availability. The is_hdr and video_resolut',
    `channel_id` BIGINT COMMENT 'Reference to the broadcast channel on which this EPG entry is scheduled for playout. Links to the channel master record in the scheduling domain.',
    `content_rating_id` BIGINT COMMENT 'Foreign key linking to compliance.content_rating. Business justification: EPG displays must show accurate content ratings for viewer guidance, V-chip filtering, and watershed compliance. Regulatory requirement in UK (Ofcom) and US (FCC) for electronic program guides. Denorm',
    `content_episode_id` BIGINT COMMENT 'Foreign key linking to content.content_episode. Business justification: EPG entries describe specific episodes; linking to content_episode enables accurate episode-level metadata delivery to EPG aggregators, rights clearance verification per episode, and repeat/rerun trac',
    `delivery_channel_id` BIGINT COMMENT 'Foreign key linking to distribution.delivery_channel. Business justification: EPG entries are published to specific delivery channels (FAST, OTT, MVPD). EPG feed generation, metadata syndication, and blackout enforcement all require knowing which delivery channel an EPG entry t',
    `distribution_agreement_id` BIGINT COMMENT 'Foreign key linking to partner.distribution_agreement. Business justification: EPG entries distributed to MVPDs must reference the distribution agreement to enforce blackout region restrictions and rights window display rules. MVPD EPG feed compliance and distribution agreement ',
    `media_asset_id` BIGINT COMMENT 'Reference to the media content asset in the Digital Asset Management system (Dalet Galaxy) that is being broadcast for this EPG entry.',
    `ott_platform_id` BIGINT COMMENT 'Foreign key linking to distribution.ott_platform. Business justification: EPG entries are published to OTT platforms for on-screen guide display. Platform-specific EPG feed versioning, metadata formatting requirements, and rights window enforcement per platform require this',
    `program_schedule_id` BIGINT COMMENT 'Foreign key linking to scheduling.program_schedule. Business justification: An EPG entry is published from a specific program schedule version. Linking epg_entry.program_schedule_id → program_schedule enables EPG publishing workflows to directly associate published guide entr',
    `rights_availability_window_id` BIGINT COMMENT 'Foreign key linking to rights.rights_availability_window. Business justification: EPG publication workflow requires real-time validation that content is within its rights availability window before displaying to viewers. Prevents publishing unavailable content and supports automate',
    `schedule_slot_id` BIGINT COMMENT 'Reference to the approved schedule slot from which this EPG entry was derived. Represents the authoritative playout scheduling record in Ericsson MediaFirst.',
    `daypart_id` BIGINT COMMENT 'Foreign key linking to scheduling.daypart. Business justification: EPG entries require daypart linkage for audience reach estimation, program discovery optimization, and daypart-based content recommendations. Creates new scheduling_daypart_id FK (role-prefixed to avo',
    `series_id` BIGINT COMMENT 'Foreign key linking to content.series. Business justification: Series-level EPG reporting (e.g., all episodes of a series airing this week, series completion tracking for VOD catch-up) requires linking EPG entries to content.series. EPG aggregators use series gro',
    `syndication_agreement_id` BIGINT COMMENT 'Foreign key linking to partner.syndication_agreement. Business justification: EPG entries for syndicated content must reference the syndication agreement to display correct rights window information, apply territory blackout flags, and enforce run-count compliance in EPG feeds ',
    `talent_profile_id` BIGINT COMMENT 'Foreign key linking to talent.talent_profile. Business justification: EPG metadata includes featured talent names for viewer discovery, search functionality, and promotional purposes. Broadcasters link talent profiles to EPG entries to enable find shows with this actor',
    `title_id` BIGINT COMMENT 'Foreign key linking to content.title. Business justification: EPG feed generation and metadata syndication require linking EPG entries to canonical title records for accurate program metadata delivery to aggregators (TiVo, Gracenote). A broadcast domain expert e',
    `holdback_id` BIGINT COMMENT 'Foreign key linking to rights.holdback. Business justification: EPG blackout entries (is_blackout, blackout_region_codes) are driven by holdback records. EPG distribution systems need direct holdback reference for real-time blackout enforcement without traversing ',
    `version_id` BIGINT COMMENT 'Foreign key linking to content.version. Business justification: EPG feeds must specify which version (language, resolution, HDR format) is broadcasting so downstream platforms display correct technical metadata. Broadcast operations require version-level EPG accur',
    `ad_pod_count` STRING COMMENT 'The number of ad pods (groups of advertisements within a break) scheduled within this program. Used for advertising inventory planning, Wide Orbit traffic scheduling, and revenue forecasting.',
    `blackout_region_codes` STRING COMMENT 'Comma-separated list of geographic region or market codes where this program is subject to broadcast blackout restrictions. Used by distribution systems to suppress EPG entry delivery in restricted markets. Populated only when is_blackout is True.',
    `broadcast_date` DATE COMMENT 'The calendar date on which this program is scheduled to air, in yyyy-MM-dd format. Used for day-level EPG grid display, daypart assignment, and schedule reporting.',
    `distribution_window` STRING COMMENT 'The distribution window or release strategy under which this EPG entry is being broadcast, reflecting the windowing strategy for sequential content release. Determines rights availability and platform eligibility per Rightsline contract terms.. Valid values are `linear|svod|avod|tvod|fast|syndication`',
    `duration_seconds` STRING COMMENT 'The total scheduled duration of the program in seconds, derived from the difference between scheduled start and end times. Used for EPG display, ad pod planning, and playout automation validation.',
    `eidr` STRING COMMENT 'The Entertainment Identifier Registry (EIDR) identifier for this content, providing a universal content identifier used across the media supply chain for content tracking, rights management, and EPG data exchange with MVPDs and vMVPDs.. Valid values are `^10.5240/[0-9A-F]{4}-[0-9A-F]{4}-[0-9A-F]{4}-[0-9A-F]{4}-[0-9A-F]{4}-[0-9A-F]{1}$`',
    `entry_status` STRING COMMENT 'The current lifecycle status of this EPG entry within the scheduling workflow. draft indicates pending review; approved indicates cleared for distribution; published indicates actively distributed to EPG feeds; cancelled indicates removed from schedule; expired indicates the broadcast window has passed.. Valid values are `draft|approved|published|cancelled|expired`',
    `epg_entry_code` STRING COMMENT 'Externally distributed business identifier for this EPG entry, used in feeds delivered to MVPDs, vMVPDs, set-top boxes, and digital platforms for program discovery. Format: EPG-{CHANNEL}-{YYYYMMDD}-{HHMMSS}.. Valid values are `^EPG-[A-Z0-9]{3,10}-[0-9]{8}-[0-9]{6}$`',
    `epg_feed_version` STRING COMMENT 'The version number of this EPG entry record as distributed in the EPG feed. Incremented each time the entry is updated and redistributed to MVPDs, vMVPDs, and digital platforms. Enables downstream systems to detect and apply updates.',
    `episode_number` STRING COMMENT 'The sequential episode number within the season for this EPG entry. Used for viewer navigation and content ordering in EPG feeds. Null for non-episodic content.',
    `episode_title` STRING COMMENT 'The title of the specific episode within a series, as displayed in the EPG. Null for non-episodic content such as feature films or standalone specials.',
    `genre_primary` STRING COMMENT 'The primary content genre classification for this EPG entry as distributed in the EPG feed (e.g., Drama, Comedy, News, Sports, Documentary, Reality). Used for viewer discovery, content filtering, and audience analytics. [ENUM-REF-CANDIDATE: drama|comedy|news|sports|documentary|reality|entertainment|children|film|music — promote to reference product]',
    `genre_secondary` STRING COMMENT 'An optional secondary genre sub-classification providing more granular content categorization for EPG discovery and audience targeting (e.g., Crime Drama, Political Comedy, Investigative Documentary).',
    `is_blackout` BOOLEAN COMMENT 'Indicates whether geographic broadcast restrictions (blackout) apply to this EPG entry (True). When True, the program is subject to blackout rules that restrict distribution in specific geographic markets per rights agreements managed in Rightsline.',
    `is_closed_caption` BOOLEAN COMMENT 'Indicates whether closed captioning (CC) is available for this program (True). Distributed in EPG feeds for accessibility compliance and viewer information. Required for FCC closed captioning regulatory compliance.',
    `is_hdr` BOOLEAN COMMENT 'Indicates whether this program is available in High Dynamic Range (HDR) format (True). Distributed in EPG feeds to inform viewers and set-top boxes of enhanced picture quality availability.',
    `is_live` BOOLEAN COMMENT 'Indicates whether this EPG entry represents a live broadcast event (True) as opposed to a pre-recorded or time-shifted program (False). Drives playout automation configuration in Ericsson MediaFirst and is distributed in EPG feeds for viewer-facing live indicators.',
    `is_new_episode` BOOLEAN COMMENT 'Indicates whether this EPG entry represents a new, first-run episode (True) or a repeat/rerun broadcast (False). Distributed in EPG feeds for viewer-facing NEW indicators and drives audience measurement prioritization.',
    `is_simulcast` BOOLEAN COMMENT 'Indicates whether this program is being simultaneously broadcast across multiple platforms or channels (simulcast). When True, the same content is distributed concurrently on linear and digital/OTT platforms.',
    `isan` STRING COMMENT 'The International Standard Audiovisual Number (ISAN) uniquely identifying this audiovisual work globally. Used for rights management, content identification across platforms, and interoperability with Rightsline and international content registries.. Valid values are `^[0-9A-F]{4}-[0-9A-F]{4}-[0-9A-F]{4}-[0-9A-F]{4}-[0-9A-F]{1}-[0-9A-F]{4}-[0-9A-F]{4}-[0-9A-F]{1}$`',
    `language_code` STRING COMMENT 'The primary audio language of the program, expressed as a three-letter ISO 639-2 language code (e.g., eng for English, spa for Spanish). Used in EPG feeds for language filtering and accessibility compliance.. Valid values are `^[a-z]{3}$`',
    `last_updated_timestamp` TIMESTAMP COMMENT 'The date and time when this EPG entry record was most recently modified, including schedule changes, metadata updates, or status transitions. Used for change detection in downstream EPG feed distribution and audit trail.',
    `published_timestamp` TIMESTAMP COMMENT 'The date and time when this EPG entry was first published and distributed to external EPG feeds (MVPDs, vMVPDs, set-top boxes, digital platforms). Serves as the record audit created timestamp for this data product.',
    `rights_window_end` DATE COMMENT 'The end date of the broadcast rights window during which this content is cleared for transmission on this channel. After this date, the content enters a holdback period and cannot be broadcast without rights renewal in Rightsline.',
    `rights_window_start` DATE COMMENT 'The start date of the broadcast rights window during which this content is cleared for transmission on this channel. Derived from Rightsline contract availabilities and used to validate schedule compliance.',
    `scheduled_end_time` TIMESTAMP COMMENT 'The precise date and time at which this program is scheduled to end broadcast on the channel. Used to calculate program duration and to sequence adjacent EPG entries in the linear channel grid.',
    `scheduled_start_time` TIMESTAMP COMMENT 'The precise date and time at which this program is scheduled to begin broadcast on the channel, expressed in ISO 8601 format with timezone offset. This is the principal business event timestamp for the EPG entry and drives all downstream playout automation in Ericsson MediaFirst.',
    `scte35_cue_out_time` TIMESTAMP COMMENT 'The timestamp of the SCTE-35 splice_insert cue-out signal marking the start of an ad break opportunity within this program. Used by Dynamic Ad Insertion (DAI) systems and Wide Orbit traffic systems for ad pod placement and automated ad scheduling.',
    `season_number` STRING COMMENT 'The season number within the series for this episode. Used for EPG display and content navigation. Null for non-episodic or non-seasonal content.',
    `synopsis_long` STRING COMMENT 'A detailed program description (typically up to 500 characters) distributed in EPG feeds for display on digital platforms, OTT apps, and web-based program guides. Sourced from Dalet Galaxy content metadata.',
    `synopsis_short` STRING COMMENT 'A brief program description (typically up to 100 characters) distributed in EPG feeds for display on set-top boxes and digital platforms with limited screen real estate. Sourced from Dalet Galaxy content metadata.',
    `total_ad_break_duration_seconds` STRING COMMENT 'The total cumulative duration in seconds of all scheduled ad breaks within this program. Used for advertising inventory management, compliance with ad load regulations, and Wide Orbit traffic scheduling.',
    `video_resolution` STRING COMMENT 'The video resolution format of this program as distributed in the EPG feed (e.g., SD, HD, FHD, UHD/4K). Used for viewer-facing display in EPG interfaces and for platform compatibility routing.. Valid values are `SD|HD|FHD|UHD|4K|8K`',
    CONSTRAINT pk_epg_entry PRIMARY KEY(`epg_entry_id`)
) COMMENT 'Published Electronic Program Guide record distributed to MVPDs, vMVPDs, set-top boxes, and digital platforms for viewer-facing program discovery. Captures program title, episode title, series name, genre, content rating (MPA), short and long synopsis, start/end time, channel, language, closed-caption flag, HDR/resolution flag, ISAN/EIDR identifier, and distribution window. Derived from approved schedule slots and enriched with content metadata for consumer-facing EPG feeds.';

CREATE OR REPLACE TABLE `media_broadcasting_ecm`.`scheduling`.`ad_break` (
    `ad_break_id` BIGINT COMMENT 'Unique surrogate identifier for the ad break (ad pod) record within the scheduling domain. Primary key for this entity.',
    `channel_id` BIGINT COMMENT 'Reference to the broadcast channel on which this ad break is scheduled for playout. Supports multi-channel scheduling and channel-level inventory reporting.',
    `dai_configuration_id` BIGINT COMMENT 'Foreign key linking to distribution.dai_configuration. Business justification: Linear ad breaks drive DAI stitching rules when simulcast to OTT. Operations teams configure DAI parameters (max pod duration, fill rate targets, frequency caps) per break type and daypart to ensure c',
    `daypart_id` BIGINT COMMENT 'Foreign key linking to scheduling.daypart. Business justification: Ad break currently stores daypart_code as a STRING. This should be normalized to FK to the daypart reference table. Ad break pricing, GRP targets, and inventory management all depend on daypart attrib',
    `delivery_channel_id` BIGINT COMMENT 'Foreign key linking to distribution.delivery_channel. Business justification: Ad breaks are sold and delivered per delivery channel. Ad operations and traffic systems need the delivery channel association to apply channel-specific ad pod rules, DAI configuration, and revenue at',
    `market_coverage_id` BIGINT COMMENT 'Foreign key linking to audience.market_coverage. Business justification: Ad breaks carry blackout_restricted and content_restriction_code flags that are market-specific. Linking ad_break to market_coverage enables market-level ad restriction enforcement, blackout complianc',
    `political_ad_record_id` BIGINT COMMENT 'Foreign key linking to compliance.political_ad_record. Business justification: Political ad breaks require detailed public inspection file documentation per FCC Section 315 (reasonable access, lowest unit charge). Each political ad break must link to compliance record for public',
    `program_rundown_id` BIGINT COMMENT 'Foreign key linking to scheduling.program_rundown. Business justification: Ad breaks within a live or studio program are planned as part of the program rundown (rundown_item records with ad_pod_flag=true). Linking ad_break.program_rundown_id → program_rundown enables reconci',
    `revenue_stream_id` BIGINT COMMENT 'Foreign key linking to finance.revenue_stream. Business justification: Ad breaks are the primary advertising revenue mechanism. Revenue recognition, sales reconciliation, and makegood accounting all depend on ad-break-to-revenue-stream mapping. Essential for advertising ',
    `schedule_slot_id` BIGINT COMMENT 'Reference to the parent schedule slot within which this ad break is positioned. Links the ad break to its containing program or interstitial window in the linear channel grid.',
    `actual_duration_seconds` STRING COMMENT 'The actual total duration of the ad break as recorded during playout by the Ericsson MediaFirst automation system. Used for post-log reconciliation, affidavit generation, and makegood assessment when actual duration deviates from planned.',
    `actual_start_time` TIMESTAMP COMMENT 'The actual wall-clock time at which the ad break commenced during playout, as recorded by the Ericsson MediaFirst automation system. Used for affidavit generation and post-log reconciliation against the scheduled start time.',
    `affidavit_generated` BOOLEAN COMMENT 'Indicates whether a proof-of-broadcast affidavit has been generated for this ad break in the Wide Orbit traffic system following confirmed playout. Affidavits are required for advertiser billing reconciliation and regulatory compliance.',
    `automation_event_code` STRING COMMENT 'The event identifier assigned by the Ericsson MediaFirst playout automation system to the break trigger event. Used to correlate the scheduled ad break with the actual playout automation log for post-log reconciliation and technical fault analysis.',
    `avail_count` STRING COMMENT 'The total number of individual advertising avail slots (unit positions) within this ad break pod. Each avail represents a discrete sellable unit (e.g., a 30-second spot position). Used for inventory capacity planning and traffic scheduling.',
    `blackout_restricted` BOOLEAN COMMENT 'Indicates whether this ad break is subject to geographic blackout restrictions that prevent its broadcast or streaming in specific markets or regions. When true, downstream distribution systems must apply blackout logic per rights and regulatory obligations.',
    `break_position` STRING COMMENT 'Positional classification of the ad break relative to the surrounding program content. pre-roll = before program content begins; mid-roll = within program content; post-roll = after program content ends; interstitial = between programs in the schedule grid.. Valid values are `pre-roll|mid-roll|post-roll|interstitial`',
    `break_status` STRING COMMENT 'Current lifecycle status of the ad break within the scheduling and playout workflow. scheduled = planned but not yet confirmed; confirmed = traffic-confirmed with sold inventory; aired = playout completed and affidavit-eligible; cancelled = removed from schedule; hold = temporarily suspended pending resolution.. Valid values are `scheduled|confirmed|aired|cancelled|hold`',
    `break_type` STRING COMMENT 'Classification of the ad break by inventory ownership and commercial purpose. local_avail = inventory sold by local affiliate; network_avail = inventory sold by the network; promotional = house promotional content; public_service = public service announcements; emergency = emergency alert system override. Drives revenue attribution and traffic scheduling rules.. Valid values are `local_avail|network_avail|promotional|public_service|emergency`',
    `broadcast_date` DATE COMMENT 'The calendar date on which this ad break is scheduled to air, expressed in the channels broadcast day convention (which may differ from the wall-clock date for late-night programming). Used for daily traffic scheduling, affidavit generation, and revenue reporting.',
    `content_restriction_code` STRING COMMENT 'A code indicating any content category restrictions applicable to advertising within this break (e.g., no alcohol ads during childrens programming, no competitor ads). Enforced by the traffic system during ad assignment. [ENUM-REF-CANDIDATE: NO_ALCOHOL|NO_GAMBLING|NO_PHARMA|NO_COMPETITOR|CHILDREN_SAFE|NONE — promote to reference product]',
    `created_timestamp` TIMESTAMP COMMENT 'The timestamp when this ad break record was first created in the scheduling system. Serves as the RECORD_AUDIT_CREATED field for data lineage, audit trail, and Silver layer ingestion tracking.',
    `currency_code` STRING COMMENT 'ISO 4217 three-letter currency code for the rate card CPM and any monetary values associated with this ad break (e.g., USD, GBP, EUR). Supports multi-currency operations for international broadcast networks.. Valid values are `^[A-Z]{3}$`',
    `dai_eligible` BOOLEAN COMMENT 'Indicates whether this ad break is enabled for Dynamic Ad Insertion (DAI), allowing server-side ad replacement for OTT/streaming simulcast audiences. When true, the break is eligible for addressable advertising via DAI platforms such as those integrated with Akamai CDN.',
    `epg_break_label` STRING COMMENT 'The human-readable label or descriptor for this ad break as it appears in the Electronic Program Guide (EPG) and scheduling rundown. Used by traffic coordinators and scheduling operators to identify breaks in the EPG interface.',
    `grp_target` DECIMAL(18,2) COMMENT 'The target Gross Rating Point (GRP) value for this ad break, representing the expected total audience delivery as a percentage of the total target population. Used for audience guarantee tracking and campaign delivery reporting against Nielsen ratings.',
    `makegood_required` BOOLEAN COMMENT 'Indicates whether a makegood (compensatory ad spot) is required for this break due to a failure to air as contracted — for example, due to preemption, technical failure, or underdelivery. Triggers makegood workflow in Wide Orbit.',
    `max_duration_seconds` STRING COMMENT 'The maximum allowable duration of the ad break in seconds, representing the hard ceiling for total ad content that may be inserted. Exceeding this value would cause schedule overrun. May differ from planned duration when flex time is permitted.',
    `nielsen_program_rating` DECIMAL(18,2) COMMENT 'The Nielsen audience rating for the program surrounding this ad break, representing the percentage of total TV households tuned in. Used for CPM calculation, audience guarantee assessment, and scatter market pricing.',
    `planned_duration_seconds` STRING COMMENT 'The planned total duration of the ad break (ad pod) in seconds as defined in the program schedule. Represents the total sellable commercial time allocated to this break. Standard pod durations are typically 30, 60, 90, 120, or 180 seconds.',
    `pod_number` STRING COMMENT 'The pod number identifying this ad break within the broadcast day for the channel. Distinct from sequence_number (which is relative to the program); pod_number is the channel-day-level ordinal used in traffic scheduling and affidavit reporting.',
    `preemption_reason` STRING COMMENT 'The reason code explaining why this ad break was preempted or cancelled if it did not air as scheduled. Used for makegood processing, revenue assurance, and operational reporting. none when the break aired as planned.. Valid values are `breaking_news|emergency_alert|technical_failure|rights_conflict|schedule_change|none`',
    `rate_card_cpm` DECIMAL(18,2) COMMENT 'The published rate card CPM (Cost Per Mille — cost per 1,000 audience impressions) for this ad break, expressed in the local currency. Represents the base pricing for inventory in this break before negotiated discounts. Used for revenue forecasting and yield management.',
    `scheduled_start_time` TIMESTAMP COMMENT 'The planned wall-clock date and time at which the ad break is scheduled to begin on the linear channel. Expressed in the channels broadcast timezone. This is the principal BUSINESS_EVENT_TIMESTAMP for the break.',
    `sequence_number` STRING COMMENT 'Ordinal position of this ad break within the parent schedule slot or program. Used to order multiple breaks within a single program (e.g., break 1, break 2, break 3) for traffic scheduling and playout automation.',
    `simulcast_eligible` BOOLEAN COMMENT 'Indicates whether this ad break is included in the simultaneous multi-platform broadcast (simulcast) of the channel. When false, the break may be suppressed or replaced on simulcast streams (e.g., OTT, vMVPD).',
    `sold_avail_count` STRING COMMENT 'The number of individual avail slots within this break that have been sold and assigned to advertiser spots in the Wide Orbit traffic system. Used with avail_count to compute sellout rate and unsold inventory.',
    `sold_duration_seconds` STRING COMMENT 'The total duration in seconds of ad inventory within this break that has been sold to advertisers via the Wide Orbit traffic system. Used to calculate unsold (remnant) inventory and sellout rate for revenue assurance reporting.',
    `updated_timestamp` TIMESTAMP COMMENT 'The timestamp when this ad break record was most recently modified in the scheduling system. Serves as the RECORD_AUDIT_UPDATED field for change tracking, incremental data pipeline processing, and audit compliance.',
    `wide_orbit_break_code` STRING COMMENT 'The externally-known break identifier assigned by the Wide Orbit traffic and billing system. Used to reconcile ad break inventory between the scheduling domain and the ad sales/traffic fulfillment workflow. This is the BUSINESS_IDENTIFIER for the break as known to the traffic system.',
    CONSTRAINT pk_ad_break PRIMARY KEY(`ad_break_id`)
) COMMENT 'Commercial break (ad pod) within a schedule slot — capturing break position (pre-roll, mid-roll, post-roll), sequence number, planned and maximum pod duration, break type (local avail, network avail, promotional), SCTE-35 cue-in/cue-out marker references, DAI eligibility flag, and Wide Orbit traffic system break ID. The structural container for sellable ad inventory within the linear schedule, linking scheduling to advertising sales fulfillment.';

CREATE OR REPLACE TABLE `media_broadcasting_ecm`.`scheduling`.`simulcast_config` (
    `simulcast_config_id` BIGINT COMMENT 'Unique surrogate identifier for the simulcast configuration record. Primary key for this entity in the Databricks Silver Layer.',
    `abr_profile_id` BIGINT COMMENT 'Reference to the Adaptive Bitrate (ABR) streaming profile applied to the target simulcast feed for OTT delivery. Defines the bitrate ladder (HLS or MPEG-DASH renditions) used by Akamai CDN for adaptive streaming to end-user devices.',
    `accessibility_obligation_id` BIGINT COMMENT 'Foreign key linking to compliance.accessibility_obligation. Business justification: Simulcast configurations carry audio_description_passthrough and closed_caption_passthrough settings that must comply with specific accessibility obligations (CVAA, FCC closed captioning rules for IP-',
    `affiliate_agreement_id` BIGINT COMMENT 'Foreign key linking to partner.affiliate_agreement. Business justification: Affiliate agreements contain simulcast_requirement_flag and digital_rights_included_flag that govern simulcast configurations for affiliate stations. Linking simulcast_config to the affiliate agreemen',
    `dai_configuration_id` BIGINT COMMENT 'Foreign key linking to distribution.dai_configuration. Business justification: Simulcast routes require DAI stitching rules when ad insertion differs between linear SCTE-35 cues and OTT server-side stitching. Technical operations configure DAI per simulcast to handle ad pod subs',
    `delivery_channel_id` BIGINT COMMENT 'Foreign key linking to distribution.delivery_channel. Business justification: Simulcast configurations define simultaneous distribution across delivery channels. The target delivery channel for a simulcast config is needed for DAI substitution rules, blackout enforcement, and r',
    `distribution_agreement_id` BIGINT COMMENT 'Foreign key linking to partner.distribution_agreement. Business justification: Simulcast configurations are authorized and governed by distribution agreements that specify streaming rights, simulcast requirements, and DRM obligations. Linking simulcast_config to the governing di',
    `drm_policy_id` BIGINT COMMENT 'Foreign key linking to distribution.drm_policy. Business justification: Simulcast configurations specify DRM requirements; drm_scheme is a denormalized plain attribute. Replacing with FK to drm_policy normalizes DRM enforcement, enables automated policy application during',
    `format_specification_id` BIGINT COMMENT 'Foreign key linking to mediaasset.format_specification. Business justification: Simulcast configurations define the output format for each distribution platform (HLS 1080p for OTT, SD H.264 for cable). Linking to format_specification enables automated transcode job creation and f',
    `license_agreement_id` BIGINT COMMENT 'Foreign key linking to rights.license_agreement. Business justification: Simulcast configurations must be authorized by a license agreement granting simulcast rights for the specific territory and platform. Distribution teams verify license agreement simulcast permissions ',
    `channel_id` BIGINT COMMENT 'Reference to the backup or secondary source channel used by Ericsson MediaFirst failover automation when the primary source channel becomes unavailable. Supports broadcast continuity and SLA compliance.',
    `rights_territory_id` BIGINT COMMENT 'Foreign key linking to rights.rights_territory. Business justification: simulcast_config.rights_territory_code is a denormalized reference to rights_territory. Simulcast configurations are territory-specific; the rights_territory record defines regulatory parameters, blac',
    `partner_id` BIGINT COMMENT 'Foreign key linking to partner.partner_partner. Business justification: Simulcast distribution agreements are with specific partners (cable operators, streaming platforms, syndication partners). Critical for multi-platform distribution tracking, partner SLA compliance, an',
    `source_channel_id` BIGINT COMMENT 'Reference to the originating linear broadcast channel whose feed is being simulcast to one or more target channels or platforms. Drives Ericsson MediaFirst multi-feed automation as the master playout source.',
    `streaming_endpoint_id` BIGINT COMMENT 'Foreign key linking to distribution.streaming_endpoint. Business justification: Simulcast configurations map linear channels to specific OTT delivery endpoints for live streaming workflows. Operations teams configure CDN routing, failover paths, and geo-restrictions per simulcast',
    `subscription_plan_id` BIGINT COMMENT 'Foreign key linking to subscriber.subscription_plan. Business justification: Simulcast configurations (e.g., 4K HDR streams, multi-audio) are gated to specific subscription plan tiers in OTT operations. This FK enables the distribution system to enforce plan-level simulcast el',
    `target_channel_id` BIGINT COMMENT 'Reference to the destination channel or platform that receives the simulcast feed from the source channel. May represent a linear channel, OTT platform feed, HD/SD variant, or secondary distribution outlet.',
    `ad_pod_substitution` BOOLEAN COMMENT 'Indicates whether the ad pods (groups of ads in a break) from the source linear feed are substituted with alternative ad content on the target simulcast feed. Distinct from DAI — covers cases where static alternate ad content replaces source pods without dynamic targeting.',
    `audio_description_passthrough` BOOLEAN COMMENT 'Indicates whether the audio description (video description) secondary audio track is passed through from the source to the target simulcast feed. Required for FCC accessibility compliance for visually impaired audiences on qualifying broadcast and MVPD platforms.',
    `blackout_enforced` BOOLEAN COMMENT 'Indicates whether geographic broadcast blackout restrictions are enforced on the target simulcast feed. When true, blackout rules (e.g., sports rights geographic restrictions) are applied to suppress content in restricted territories on the target platform.',
    `cdn_origin_path` STRING COMMENT 'The Akamai CDN origin ingest path or stream key for the target simulcast feed. Used to route the encoded simulcast stream from Ericsson MediaFirst playout to the CDN origin for OTT and digital distribution.',
    `closed_caption_passthrough` BOOLEAN COMMENT 'Indicates whether closed caption data from the source channel feed is passed through to the target simulcast feed. Required for FCC accessibility compliance on all broadcast and MVPD distribution platforms.',
    `config_code` STRING COMMENT 'Externally-known alphanumeric business identifier for this simulcast configuration, used in Ericsson MediaFirst automation rules, runsheets, and operational documentation. Unique across all active configurations.. Valid values are `^[A-Z0-9_-]{3,30}$`',
    `config_description` STRING COMMENT 'Free-text operational description of the simulcast configuration, including business rationale, special handling instructions, and notes for scheduling and playout operations teams.',
    `config_name` STRING COMMENT 'Human-readable descriptive name for the simulcast configuration (e.g., CNN HD to CNN SD Full-Feed, Linear to OTT Time-Shifted +1hr). Used in EPG management and scheduling operations.',
    `content_rating_restriction` STRING COMMENT 'Maximum content rating permitted on the target simulcast feed per Motion Picture Association (MPA) and FCC content rating standards. Ensures age-appropriate content controls are applied on the target platform, particularly for COPPA-regulated childrens platforms.. Valid values are `TV-Y|TV-Y7|TV-G|TV-PG|TV-14|TV-MA`',
    `created_timestamp` TIMESTAMP COMMENT 'The timestamp when this simulcast configuration record was first created in the system, in ISO 8601 format (yyyy-MM-ddTHH:mm:ss.SSSXXX). Provides audit trail for configuration lifecycle management.',
    `dai_enabled` BOOLEAN COMMENT 'Indicates whether Dynamic Ad Insertion (DAI) is active on the target simulcast feed, replacing linear ad pods with dynamically served targeted advertisements. Applicable primarily to OTT and AVOD distribution platforms.',
    `distribution_platform` STRING COMMENT 'The delivery platform type of the target channel or feed. Distinguishes linear broadcast from OTT (Over-The-Top), MVPD (Multichannel Video Programming Distributor), vMVPD (Virtual MVPD), FAST (Free Ad-Supported Streaming Television), cable, satellite, IPTV, or web delivery. [ENUM-REF-CANDIDATE: linear|ott|mvpd|vmvpd|fast|cable|satellite|iptv|web — promote to reference product]',
    `effective_from` DATE COMMENT 'The calendar date from which this simulcast configuration becomes operationally active and is applied by Ericsson MediaFirst playout automation. Aligns with schedule activation windows in the EPG.',
    `effective_until` DATE COMMENT 'The calendar date on which this simulcast configuration expires and is deactivated. Nullable for open-ended configurations with no planned end date. Supports windowing and holdback period management.',
    `epg_sync_enabled` BOOLEAN COMMENT 'Indicates whether the Electronic Program Guide (EPG) metadata from the source channel schedule is automatically synchronized to the target simulcast channels EPG. When true, program titles, descriptions, and ratings are mirrored to the target channel grid.',
    `failover_mode` STRING COMMENT 'Defines the failover behavior for the simulcast target feed in Ericsson MediaFirst when the source channel signal is lost or degraded. Automatic triggers immediate failover to backup source; manual requires operator intervention; disabled means no failover is configured.. Valid values are `automatic|manual|disabled`',
    `graphics_passthrough` BOOLEAN COMMENT 'Indicates whether on-screen graphics, lower-thirds, and channel branding overlays from the source channel are passed through to the target simulcast feed. When false, the target feed may apply its own branding or suppress source graphics.',
    `mediafirst_config_ref` STRING COMMENT 'The external configuration reference identifier assigned by Ericsson MediaFirst playout automation system to this simulcast configuration. Used for reconciliation between the data lakehouse Silver Layer and the operational playout system.. Valid values are `^[A-Z0-9_-]{1,50}$`',
    `must_carry_compliant` BOOLEAN COMMENT 'Indicates whether this simulcast configuration satisfies must-carry obligations requiring MVPDs to carry local broadcast stations. Ensures regulatory compliance tracking for FCC must-carry and retransmission consent requirements.',
    `priority_rank` STRING COMMENT 'Numeric priority ranking for this simulcast configuration when multiple configurations apply to the same source channel simultaneously. Lower values indicate higher priority. Used by Ericsson MediaFirst to resolve conflicts in multi-feed automation.',
    `scte35_cue_passthrough` BOOLEAN COMMENT 'Indicates whether SCTE-35 digital program insertion cue markers from the source channel are passed through to the target simulcast feed. When true, ad break triggers and blackout signals are propagated to the target. Critical for DAI (Dynamic Ad Insertion) on OTT platforms.',
    `simulcast_config_status` STRING COMMENT 'Current lifecycle state of the simulcast configuration record. Active configurations are processed by Ericsson MediaFirst automation. Suspended configurations are temporarily halted (e.g., rights blackout). Draft configurations are under review prior to activation.. Valid values are `active|inactive|pending|suspended|draft`',
    `simulcast_type` STRING COMMENT 'Classification of the simulcast relationship: full_feed (identical content and timing), partial (selected programs only), time_shifted (offset delay applied), simulcast_only (live events only), ad_substituted (DAI replaces linear ad pods on target). Drives automation logic in Ericsson MediaFirst.. Valid values are `full_feed|partial|time_shifted|simulcast_only|ad_substituted`',
    `time_offset_seconds` STRING COMMENT 'The delay in seconds applied to the target feed relative to the source channel. Zero for true simultaneous simulcast. Positive values indicate a time-shifted delay (e.g., +3600 for a +1 hour catch-up feed). Used by Ericsson MediaFirst to schedule playout offset.',
    `updated_timestamp` TIMESTAMP COMMENT 'The timestamp when this simulcast configuration record was last modified, in ISO 8601 format (yyyy-MM-ddTHH:mm:ss.SSSXXX). Supports change tracking and audit compliance for playout configuration governance.',
    `watermark_enabled` BOOLEAN COMMENT 'Indicates whether a forensic or visible watermark is applied to the target simulcast feed for content protection, piracy detection, and rights enforcement tracking. Supports MPA anti-piracy compliance.',
    CONSTRAINT pk_simulcast_config PRIMARY KEY(`simulcast_config_id`)
) COMMENT 'Configuration record defining a simulcast relationship where a single program or schedule is broadcast simultaneously across multiple channels or platforms (e.g., linear + OTT, HD + SD, primary + secondary feed). Captures source channel, target channel or platform, simulcast type (full-feed, partial, time-shifted), offset in seconds, audio/video profile mapping, and active date range. Drives Ericsson MediaFirst multi-feed automation.';

CREATE OR REPLACE TABLE `media_broadcasting_ecm`.`scheduling`.`playout_event` (
    `playout_event_id` BIGINT COMMENT 'Unique surrogate identifier for each as-run playout event record in the Ericsson MediaFirst as-run log. Serves as the primary key for this table.',
    `abr_profile_id` BIGINT COMMENT 'Foreign key linking to distribution.abr_profile. Business justification: OTT/streaming playout events use a specific ABR profile for encoding and delivery. QoS reporting, post-transmission bitrate analysis, and CDN cost attribution require knowing which ABR profile was app',
    `acquisition_deal_id` BIGINT COMMENT 'Foreign key linking to partner.acquisition_deal. Business justification: Playout events for acquired content reference the acquisition deal for run-count tracking and royalty/residual calculation. Rights management and finance operations require linking confirmed playout e',
    `appearance_schedule_id` BIGINT COMMENT 'Foreign key linking to talent.appearance_schedule. Business justification: appearance_schedule explicitly tracks playout_system_sync_status and playout_system_sync_timestamp, confirming this sync relationship is a real operational process. Playout operations teams reconcile ',
    `asset_version_id` BIGINT COMMENT 'Foreign key linking to mediaasset.asset_version. Business justification: As-run logs and affidavit generation for advertiser proof-of-performance and rights-holder reporting require recording which exact asset version (codec, resolution, DRM scheme) was transmitted — a reg',
    `channel_id` BIGINT COMMENT 'Reference to the broadcast channel on which this playout event was transmitted. Links to the channel master record.',
    `clearance_request_id` BIGINT COMMENT 'Foreign key linking to rights.clearance_request. Business justification: As-run affidavit generation and post-broadcast rights compliance reporting require linking each playout event to the clearance request that authorized it. Enables clearance SLA measurement and post-ai',
    `closed_caption_record_id` BIGINT COMMENT 'Foreign key linking to compliance.closed_caption_record. Business justification: Each playout event must have corresponding closed caption compliance record for FCC CVAA accessibility reporting. Required for quarterly closed captioning quality reports and complaint response. Links',
    `content_episode_id` BIGINT COMMENT 'Foreign key linking to content.content_episode. Business justification: For episodic content, as-run logs must identify the specific episode that aired for union residuals calculation, repeat/rerun tracking, and broadcast compliance. Episode-level playout records are requ',
    `contract_id` BIGINT COMMENT 'Foreign key linking to talent.contract. Business justification: As-run playout logs are the authoritative source for guild residual calculations. The contract governing each exhibition must be directly referenced on the playout event record to support SAG-AFTRA/WG',
    `cost_center_id` BIGINT COMMENT 'Foreign key linking to finance.cost_center. Business justification: Playout events incur transmission and playout automation costs. Transmission cost allocation, actual-vs-budget variance analysis, and operational cost accounting require event-to-cost-center mapping. ',
    `daypart_id` BIGINT COMMENT 'Foreign key linking to scheduling.daypart. Business justification: Playout event currently stores daypart_code as a STRING. As-run logs need to reference daypart attributes for affidavit generation, Nielsen reporting, and GRP calculation. Normalizing to FK enables JO',
    `delivery_channel_id` BIGINT COMMENT 'Foreign key linking to distribution.delivery_channel. Business justification: Post-transmission reconciliation, SLA reporting, and ad affidavit generation require knowing which delivery channel carried each playout event. Broadcast operations teams link playout events to delive',
    `drm_policy_id` BIGINT COMMENT 'Foreign key linking to distribution.drm_policy. Business justification: OTT/streaming playout events must apply the correct DRM policy for rights enforcement. Post-transmission compliance audits and DRM incident reporting require knowing which DRM policy governed each pla',
    `eas_log_id` BIGINT COMMENT 'Foreign key linking to compliance.eas_log. Business justification: Emergency Alert System activations during playout must be logged for FCC Part 11 compliance verification. Required for EAS test documentation and public inspection file. Links broadcast event to regul',
    `grant_id` BIGINT COMMENT 'Foreign key linking to rights.grant. Business justification: As-run records are the primary input for royalty statement calculation. Each playout event must reference the grant to apply the correct royalty rate, residual formula, and exploitation type. Automate',
    `license_agreement_id` BIGINT COMMENT 'Foreign key linking to rights.license_agreement. Business justification: As-run log reconciliation and affidavit generation require tracing each playout event to its authorizing license agreement for royalty calculation, run-count tracking, and FCC compliance reporting. Ev',
    `media_asset_id` BIGINT COMMENT 'Foreign key linking to mediaasset.media_asset. Business justification: As-run logs must capture the actual media file played for affidavit generation, FCC compliance reporting, and discrepancy analysis. Playout events record what actually aired at file level, not just ti',
    `title_id` BIGINT COMMENT 'Reference to the content asset (programme, advertisement, interstitial, or filler) that was transmitted in this playout event. Links to the content master in the Digital Asset Management system.',
    `program_rundown_id` BIGINT COMMENT 'Foreign key linking to scheduling.program_rundown. Business justification: A playout_event is the as-run log record capturing actual transmission. For live and studio programs, the playout event should reference the program_rundown it executed against, enabling post-transmis',
    `program_schedule_id` BIGINT COMMENT 'Reference to the planned program schedule entry from which this playout event was derived. Enables deviation analysis between planned and actual transmission.',
    `role_id` BIGINT COMMENT 'Foreign key linking to talent.role. Business justification: Guild residual formulas differ by role category (above-the-line vs. below-the-line). The as-run playout log must reference the specific role to calculate correct residual amounts per SAG-AFTRA/WGA agr',
    `schedule_slot_id` BIGINT COMMENT 'Foreign key linking to scheduling.schedule_slot. Business justification: Playout events are as-run logs capturing actual transmission of schedule slots. Currently playout_event links to program_schedule but not to the specific schedule_slot that was transmitted. This FK en',
    `simulcast_config_id` BIGINT COMMENT 'Foreign key linking to scheduling.simulcast_config. Business justification: A playout_event has a simulcast_flag indicating it was simulcast. Linking playout_event.simulcast_config_id → simulcast_config identifies which simulcast configuration was active during that transmiss',
    `streaming_endpoint_id` BIGINT COMMENT 'Foreign key linking to distribution.streaming_endpoint. Business justification: OTT/simulcast playout events are transmitted via a specific streaming endpoint. QoS incident correlation, CDN cost attribution, and SLA breach reporting require the streaming endpoint used per playout',
    `syndication_agreement_id` BIGINT COMMENT 'Foreign key linking to partner.syndication_agreement. Business justification: Playout events for syndicated content must reference the syndication agreement for affidavit generation, run-count decrement, and barter spot reconciliation. Syndication compliance reporting and partn',
    `talent_profile_id` BIGINT COMMENT 'Foreign key linking to talent.talent_profile. Business justification: Playout systems log actual talent appearances for affidavit generation, residual payment calculation triggers, and as-run reconciliation against talent contracts. Required for guild reporting, usage r',
    `holdback_id` BIGINT COMMENT 'Foreign key linking to rights.holdback. Business justification: As-run logs must record which holdback caused a blackout substitution for rights enforcement compliance and post-broadcast holdback audit reporting. Broadcasters must demonstrate holdback compliance t',
    `version_id` BIGINT COMMENT 'Foreign key linking to content.version. Business justification: As-run logs and compliance affidavits must record which specific version actually aired — a regulatory and rights requirement. Residuals calculations, FCC compliance filings, and Nielsen measurement a',
    `actual_duration_seconds` STRING COMMENT 'Actual transmitted duration of the playout event in seconds as recorded in the as-run log. Used for rights usage reporting, billing reconciliation, and compliance verification.',
    `actual_end_time` TIMESTAMP COMMENT 'Actual transmission end time as recorded in the Ericsson MediaFirst as-run log. Used with actual_start_time to confirm full transmission and calculate actual duration.',
    `actual_start_time` TIMESTAMP COMMENT 'Actual transmission start time as recorded in the Ericsson MediaFirst as-run log. The authoritative timestamp for affidavit generation, rights usage reporting, and regulatory proof-of-performance.',
    `affidavit_generated` BOOLEAN COMMENT 'Indicates whether a broadcast affidavit (proof-of-performance document) has been generated for this playout event in Wide Orbit. Affidavits are the evidentiary basis for advertiser billing and regulatory compliance.',
    `automation_mode` STRING COMMENT 'Operational mode of the Ericsson MediaFirst playout automation at the time of this event. auto = fully automated playout; manual = operator-controlled; override = scheduled automation overridden by operator; failover = backup/failover system active.. Valid values are `auto|manual|override|failover`',
    `blackout_flag` BOOLEAN COMMENT 'Indicates whether this playout event was subject to a geographic broadcast blackout restriction. When true, the event was blacked out in one or more markets per rights or regulatory obligations.',
    `broadcast_date` DATE COMMENT 'Calendar date on which this playout event was transmitted, expressed in the channels local broadcast day (which may differ from UTC date for overnight programming).',
    `broadcast_standard` STRING COMMENT 'Technical broadcast standard under which this playout event was transmitted. Determines encoding, modulation, and compliance requirements.. Valid values are `ATSC|DVB|ISDB|NTSC|PAL`',
    `content_rating` STRING COMMENT 'Content rating classification of the transmitted asset as defined by the Motion Picture Association (MPA) TV Parental Guidelines. Used for COPPA compliance, watershed enforcement, and FCC childrens programming obligations.. Valid values are `TV-Y|TV-Y7|TV-G|TV-PG|TV-14|TV-MA`',
    `created_timestamp` TIMESTAMP COMMENT 'Timestamp when this as-run playout event record was first ingested into the Silver layer from the Ericsson MediaFirst as-run log. Serves as the audit creation timestamp for data lineage.',
    `dai_eligible` BOOLEAN COMMENT 'Indicates whether this playout event was eligible for Dynamic Ad Insertion (DAI) on OTT/streaming platforms. Used for digital advertising reconciliation and DAI revenue attribution.',
    `dalet_asset_code` STRING COMMENT 'Asset identifier in the Dalet Galaxy Media Asset Management system for the content transmitted in this playout event. Used for digital asset reconciliation and archive linkage.',
    `event_type` STRING COMMENT 'Classification of the playout event by content category. Determines applicable rights, billing rules, and regulatory requirements. [ENUM-REF-CANDIDATE: program|commercial|promo|interstitial|filler|ident|emergency_alert — promote to reference product]',
    `failover_activated` BOOLEAN COMMENT 'Indicates whether the Ericsson MediaFirst failover/backup playout system was active during this event. When true, the primary playout chain was unavailable and the backup system handled transmission.',
    `isan_code` STRING COMMENT 'International Standard Audiovisual Number (ISAN) identifying the programme or content asset transmitted. Used for rights usage reporting and royalty calculation in Rightsline.',
    `isci_code` STRING COMMENT 'Industry Standard Commercial Identification (ISCI) code for the commercial asset transmitted in this playout event. Used for advertiser billing reconciliation and affidavit generation in Wide Orbit.. Valid values are `^[A-Z0-9]{8}$`',
    `mediafirst_event_code` STRING COMMENT 'Native event identifier assigned by Ericsson MediaFirst automation system for this as-run log entry. Used for reconciliation with the source playout system.',
    `must_carry_flag` BOOLEAN COMMENT 'Indicates whether this playout event was subject to must-carry obligations requiring mandatory channel inclusion by MVPDs. Used for regulatory compliance reporting to the FCC.',
    `playout_status` STRING COMMENT 'Outcome status of the playout event as recorded in the Ericsson MediaFirst as-run log. aired = transmitted as planned; skipped = omitted from transmission; substituted = replaced with alternate content; failed = transmission error; partial = incomplete transmission; delayed = transmitted late.. Valid values are `aired|skipped|substituted|failed|partial|delayed`',
    `rights_clearance_status` STRING COMMENT 'Rights clearance status of the content asset at the time of transmission. cleared = rights verified and valid; pending = clearance in progress; expired = rights window had lapsed; restricted = transmission was restricted. Used for rights compliance audit and Rightsline reconciliation.. Valid values are `cleared|pending|expired|restricted`',
    `scheduled_duration_seconds` STRING COMMENT 'Planned duration of the playout event in seconds as defined in the program schedule rundown. Used as the baseline for duration deviation analysis.',
    `scheduled_start_time` TIMESTAMP COMMENT 'Planned transmission start time for this event as defined in the Electronic Program Guide (EPG) and program schedule rundown. Used as the baseline for schedule deviation calculation.',
    `simulcast_flag` BOOLEAN COMMENT 'Indicates whether this playout event was simultaneously broadcast across multiple platforms (simulcast). When true, the event was transmitted on additional channels or OTT platforms concurrently.',
    `start_deviation_seconds` STRING COMMENT 'Difference in seconds between actual_start_time and scheduled_start_time. Positive values indicate late start; negative values indicate early start. Key metric for schedule adherence and SLA reporting.',
    `substitution_reason` STRING COMMENT 'Reason code explaining why the originally scheduled content was substituted with alternate content. Populated only when playout_status is substituted. Used for rights compliance and editorial audit trails.. Valid values are `rights_expired|technical_fault|editorial_decision|emergency_override|blackout|operator_override`',
    `transmission_type` STRING COMMENT 'Mode of content delivery for this playout event. linear = traditional scheduled broadcast; vod = Video On Demand; simulcast = simultaneous multi-platform; ott = Over-The-Top streaming; fast = Free Ad-Supported Streaming Television.. Valid values are `linear|vod|simulcast|ott|fast`',
    `updated_timestamp` TIMESTAMP COMMENT 'Timestamp when this playout event record was last modified in the Silver layer, for example following affidavit generation, rights clearance update, or schedule reconciliation.',
    `wide_orbit_log_code` STRING COMMENT 'Corresponding log entry identifier in Wide Orbit Traffic and Billing system. Used for advertiser billing reconciliation and affidavit generation.',
    CONSTRAINT pk_playout_event PRIMARY KEY(`playout_event_id`)
) COMMENT 'As-run log record from Ericsson MediaFirst capturing actual transmission of each schedule slot as broadcast. Records actual start/end time, duration, content ID, channel, playout status (aired, skipped, substituted, failed), automation mode (auto, manual, override), operator ID, and deviation from planned schedule in seconds. The authoritative as-run record serving as the evidentiary basis for affidavit generation, rights usage reporting, advertiser billing reconciliation, and regulatory proof-of-performance.';

CREATE OR REPLACE TABLE `media_broadcasting_ecm`.`scheduling`.`program_rundown` (
    `program_rundown_id` BIGINT COMMENT 'Unique surrogate identifier for the program rundown record in the Databricks Silver Layer. Primary key for this entity.',
    `acquisition_deal_id` BIGINT COMMENT 'Foreign key linking to partner.acquisition_deal. Business justification: Program rundowns for acquired content reference the acquisition deal for episode-level rights clearance verification and run-count decrement. Rights management operations require tracking which acquis',
    `appearance_schedule_id` BIGINT COMMENT 'Foreign key linking to talent.appearance_schedule. Business justification: Live and news program rundowns are built around confirmed talent appearance bookings. Rundown producers must verify appearance confirmation_status before approving a rundown. This is a standard pre-pr',
    `asset_version_id` BIGINT COMMENT 'Foreign key linking to mediaasset.asset_version. Business justification: Approved program rundowns must reference the QC-passed asset version for transmission. Rights clearance sign-off and playout failover decisions depend on the specific version; the existing media_asset',
    `broadcast_license_id` BIGINT COMMENT 'Foreign key linking to compliance.broadcast_license. Business justification: FCC compliance audits require linking program rundowns to the governing broadcast license to verify childrens programming quotas, EAS readiness, and political broadcasting obligations. Compliance off',
    `channel_id` BIGINT COMMENT 'Reference to the broadcast channel on which this program rundown is executed. Links to the channel master in the scheduling domain.',
    `clearance_request_id` BIGINT COMMENT 'Foreign key linking to rights.clearance_request. Business justification: Rundown approval is gated on clearance decision. Linking program_rundown to clearance_request enables tracking which clearance authorized the rundown, supporting rights clearance workflow management a',
    `content_episode_id` BIGINT COMMENT 'Reference to the episode or content asset in the content domain that this rundown is associated with. Enables linkage to content metadata, rights, and digital asset records.',
    `cost_center_id` BIGINT COMMENT 'Foreign key linking to finance.cost_center. Business justification: Program rundowns for live and news programming are produced by distinct departments (news, sports, entertainment) with separate cost centers, which may differ from the schedule-level cost center. Fina',
    `daypart_id` BIGINT COMMENT 'Foreign key linking to scheduling.daypart. Business justification: Program rundown currently stores daypart_code as a STRING. This should be normalized to FK to the daypart reference table (scheduling_daypart_id). This enables JOIN to retrieve daypart_name, rate_mult',
    `delivery_channel_id` BIGINT COMMENT 'Foreign key linking to distribution.delivery_channel. Business justification: Program rundowns are prepared per delivery channel to account for channel-specific ad pod rules, content rating restrictions, and DAI configuration. Traffic and operations teams link rundowns to deliv',
    `license_agreement_id` BIGINT COMMENT 'Foreign key linking to rights.license_agreement. Business justification: Rundown approval requires confirming the license agreement authorizes the broadcast for the scheduled territory, media type, and run count. Rights operations teams validate license terms before approv',
    `media_asset_id` BIGINT COMMENT 'Foreign key linking to mediaasset.media_asset. Business justification: Live news/sports rundowns reference specific media assets (pre-produced packages, VTR rolls, B-roll) for playout during live production. Production control systems need direct asset references for ope',
    `production_budget_id` BIGINT COMMENT 'Foreign key linking to finance.production_budget. Business justification: Program rundowns represent the detailed execution plan for a show and consume production budget (crew, facilities, talent). Finance tracks actual vs. budgeted spend at rundown level for cost control a',
    `program_schedule_id` BIGINT COMMENT 'Reference to the parent program schedule entry (Electronic Program Guide slot) that this rundown fulfills. Aligns with scheduling.program_schedule.',
    `schedule_slot_id` BIGINT COMMENT 'Foreign key linking to scheduling.schedule_slot. Business justification: A program_rundown is the detailed production rundown for a specific live or studio program airing. Each rundown corresponds to exactly one schedule_slot (the content event it supports). Adding schedul',
    `syndication_agreement_id` BIGINT COMMENT 'Foreign key linking to partner.syndication_agreement. Business justification: Program rundowns for syndicated episodes must reference the syndication agreement to track barter spot counts, per-episode run limits, and clearance obligations at the episode level. Syndication traff',
    `talent_profile_id` BIGINT COMMENT 'Foreign key linking to talent.talent_profile. Business justification: Live show rundowns (news, talk shows, morning programs) specify primary talent (anchors, hosts) for production coordination, union notification requirements, and screen time tracking. Essential for ca',
    `version_id` BIGINT COMMENT 'Foreign key linking to content.version. Business justification: Program rundowns drive playout automation; version selection (which dub, which edit) must be recorded at rundown level for technical QC sign-off and compliance. Playout systems require version-level r',
    `ad_pod_count` STRING COMMENT 'Number of commercial break ad pods (groups of ads) planned within this rundown. Used for Wide Orbit traffic scheduling and SCTE-35 cue marker planning.',
    `approved_by` STRING COMMENT 'Name or identifier of the producer or scheduling manager who approved the final rundown for transmission. Required for production accountability and compliance audit trails.',
    `approved_timestamp` TIMESTAMP COMMENT 'The date and time when the rundown was formally approved for playout. Marks the transition from approved to locked status in the production workflow.',
    `blackout_flag` BOOLEAN COMMENT 'Indicates whether geographic broadcast blackout restrictions apply to this program rundown. When True, blackout rules must be enforced by distribution systems per rights agreements managed in Rightsline.',
    `broadcast_date` DATE COMMENT 'The calendar date on which this program rundown is scheduled for transmission. Used for EPG alignment, scheduling compliance, and as-run reconciliation.',
    `content_rating` STRING COMMENT 'The TV Parental Guidelines content rating assigned to the program (e.g., TV-G, TV-14, TV-MA). Used for scheduling compliance, COPPA restrictions, and EPG display.. Valid values are `TV-Y|TV-Y7|TV-G|TV-PG|TV-14|TV-MA`',
    `created_timestamp` TIMESTAMP COMMENT 'The date and time when this rundown record was first created in the system, typically when the production team initiates show preparation in Dalet Galaxy.',
    `dai_eligible` BOOLEAN COMMENT 'Indicates whether this program rundown is eligible for Dynamic Ad Insertion (DAI) on streaming/OTT platforms. Drives ad tech configuration in Akamai CDN and Adobe Experience Platform.',
    `dalet_story_code` STRING COMMENT 'The story or rundown identifier in Dalet Galaxy Media Asset Management system. Enables traceability from the Silver Layer back to the MAM workflow for metadata, archive, and ingest operations.',
    `emergency_alert_ready` BOOLEAN COMMENT 'Indicates whether the rundown and playout configuration supports Emergency Alert System (EAS) interruption. Required for FCC broadcast compliance and emergency preparedness.',
    `last_modified_timestamp` TIMESTAMP COMMENT 'The date and time when this rundown record was last updated. Tracks the most recent editorial or operational change to the rundown for audit and version control purposes.',
    `live_flag` BOOLEAN COMMENT 'Indicates whether the program is transmitted live (True) or is a pre-recorded/tape playback (False). Drives Ericsson MediaFirst live playout mode and affects DAI eligibility and failover configuration.',
    `mediafirst_rundown_code` STRING COMMENT 'The native rundown identifier assigned by Ericsson MediaFirst playout automation system. Used for bidirectional reconciliation between the Silver Layer and the operational playout system.',
    `playout_failover_mode` STRING COMMENT 'Defines the failover strategy configured in Ericsson MediaFirst if the primary playout source fails during this program. none = no failover; backup_channel = switch to backup feed; filler_loop = play filler content; manual = operator intervention required.. Valid values are `none|backup_channel|filler_loop|manual`',
    `production_format` STRING COMMENT 'Describes the production origination format of the program. studio = produced in-house studio; remote = outside broadcast; hybrid = mixed studio and remote; tape = pre-recorded playback; simulcast = simultaneous multi-platform broadcast.. Valid values are `studio|remote|hybrid|tape|simulcast`',
    `program_content_seconds` STRING COMMENT 'Total planned duration of editorial/program content segments in seconds, excluding commercial breaks and credits. Used for content-to-ad ratio compliance reporting.',
    `program_title` STRING COMMENT 'The editorial title of the program for which this rundown is prepared (e.g., Morning News Live, Prime Time Sports). Used for display in production systems and EPG.',
    `rights_clearance_status` STRING COMMENT 'Current rights clearance status for the program content in this rundown. cleared = all rights verified for broadcast; pending = clearance in progress; restricted = broadcast blocked; expired = rights window has lapsed. Sourced from Rightsline.. Valid values are `cleared|pending|restricted|expired`',
    `rundown_code` STRING COMMENT 'Externally-known alphanumeric business identifier for the rundown, used by production teams and Ericsson MediaFirst automation to reference the show rundown. Unique within a broadcast date and channel.. Valid values are `^[A-Z0-9_-]{3,30}$`',
    `rundown_notes` STRING COMMENT 'Free-text production notes associated with the rundown, capturing special instructions, last-minute changes, talent notes, or technical advisories for the production and playout teams.',
    `rundown_status` STRING COMMENT 'Current lifecycle state of the rundown. draft = in preparation; approved = signed off by producer; locked = no further edits permitted; transmitted = playout completed; archived = retained for compliance.. Valid values are `draft|approved|locked|transmitted|archived`',
    `rundown_type` STRING COMMENT 'Classification of the program rundown by genre or production format. Drives template selection in Ericsson MediaFirst and informs segment structure expectations. [ENUM-REF-CANDIDATE: news|sports|entertainment|talk_show|documentary|magazine|special — promote to reference product]',
    `rundown_version` STRING COMMENT 'Incremental version number of the rundown, incremented each time the rundown is revised. Enables version tracking and rollback for production teams and playout automation.',
    `scheduled_end_time` TIMESTAMP COMMENT 'The planned transmission end timestamp for the program. Used to calculate total runtime and validate against EPG slot allocation.',
    `scheduled_start_time` TIMESTAMP COMMENT 'The planned transmission start timestamp for the program, including timezone offset. Used by Ericsson MediaFirst automation for playout triggering and EPG publication.',
    `scte35_cue_count` STRING COMMENT 'Number of SCTE-35 digital program insertion cue markers planned in this rundown. Used for Dynamic Ad Insertion (DAI) triggering and ad break signaling to downstream distribution systems.',
    `segment_count` STRING COMMENT 'Total number of rundown items (segments) defined in this rundown, including news blocks, interviews, commercial breaks, tosses, and credits. Used for production planning and playout validation.',
    `simulcast_flag` BOOLEAN COMMENT 'Indicates whether this program rundown is simultaneously broadcast across multiple platforms (linear, OTT, streaming). When True, simulcast platform configurations must be applied.',
    `total_ad_time_seconds` STRING COMMENT 'Total planned advertising time in seconds across all ad pods in the rundown. Used for FCC/Ofcom advertising minutage compliance and Wide Orbit traffic reconciliation.',
    `total_runtime_seconds` STRING COMMENT 'Total planned duration of the program in seconds, encompassing all segments including program content, commercial breaks, and credits. Must match the EPG slot allocation.',
    `transmitted_timestamp` TIMESTAMP COMMENT 'The actual date and time when playout of this program rundown commenced transmission. Populated by Ericsson MediaFirst upon broadcast start. Used for as-run reconciliation and affidavit generation.',
    `wide_orbit_log_code` STRING COMMENT 'The traffic log identifier in Wide Orbit used to reconcile ad pod placements in this rundown against the ad scheduling and billing system. Supports affidavit generation and as-run confirmation.',
    CONSTRAINT pk_program_rundown PRIMARY KEY(`program_rundown_id`)
) COMMENT 'Detailed production rundown for a live or studio program defining the internal segment structure — news blocks, interview segments, commercial breaks, toss segments, and closing credits. Captures program title, episode reference, total runtime, segment count, live/tape flag, rundown status, and the ordered list of rundown items with planned durations. Used by Ericsson MediaFirst automation for live show playout control and by production teams for show preparation.';

CREATE OR REPLACE TABLE `media_broadcasting_ecm`.`scheduling`.`rundown_item` (
    `rundown_item_id` BIGINT COMMENT 'Unique surrogate identifier for each individual segment or item within a program rundown. Primary key for the rundown_item entity in the Databricks Silver Layer.',
    `asset_version_id` BIGINT COMMENT 'Foreign key linking to mediaasset.asset_version. Business justification: Live and news production rundown items reference specific asset versions (proxy for preview vs. broadcast-quality for air). Playout automation systems need the exact version FK to cue the correct rend',
    `clearance_request_id` BIGINT COMMENT 'Foreign key linking to rights.clearance_request. Business justification: Individual rundown items (news clips, music cues, licensed segments) each require separate clearance. Linking rundown_item to clearance_request enables item-level clearance tracking, supporting news a',
    `content_episode_id` BIGINT COMMENT 'Foreign key linking to content.content_episode. Business justification: For scripted programming rundowns, each rundown item maps to a specific episode for rights clearance, residuals tracking, and broadcast compliance. Episode-level as-run logs are required for union res',
    `media_asset_id` BIGINT COMMENT 'Foreign key linking to mediaasset.media_asset. Business justification: Individual rundown items (VTR, PKG, VO) must reference the specific media file for playout. Production operators need asset-level metadata (duration, timecode, format) for live show execution. Distinc',
    `music_sync_license_id` BIGINT COMMENT 'Foreign key linking to rights.music_sync_license. Business justification: Cue sheet generation for music royalty reporting (ASCAP/BMI/SESAC) requires linking each rundown item containing music to its music sync license. Broadcasters are legally required to report music usag',
    `program_rundown_id` BIGINT COMMENT 'Foreign key linking to scheduling.program_rundown. Business justification: Rundown items are individual segments within a program rundown. Currently rundown_item only links to program_schedule, but it should also link to the specific program_rundown that contains it. This pr',
    `program_schedule_id` BIGINT COMMENT 'Reference to the parent program schedule (rundown header) that this item belongs to. Links the atomic rundown item to its containing broadcast schedule.',
    `role_id` BIGINT COMMENT 'Foreign key linking to talent.role. Business justification: Each rundown item represents a segment where talent performs a specific role (anchor, correspondent, guest). The role entity captures character name, billing position, and screen time minutes — all ne',
    `talent_profile_id` BIGINT COMMENT 'Foreign key linking to talent.talent_profile. Business justification: Individual rundown segments feature specific talent (correspondents, panelists, guests) requiring tracking for segment-level screen time calculation, residual eligibility determination, and credit att',
    `title_id` BIGINT COMMENT 'Foreign key linking to content.title. Business justification: Rundown items reference specific content titles for playout automation rights clearance checks and as-run log reconciliation. Traffic systems must resolve item_title to a canonical title record for bi',
    `version_id` BIGINT COMMENT 'Foreign key linking to content.version. Business justification: Playout operations require knowing which specific content version (language dub, edit, format) is in each rundown item for QC verification, compliance reporting, and as-run log accuracy. Version selec',
    `actual_duration_seconds` STRING COMMENT 'Real elapsed duration of the rundown item in seconds as recorded during or after playout. Compared against planned_duration_seconds for show timing analysis and as-run log reconciliation.',
    `actual_end_time` TIMESTAMP COMMENT 'Actual wall-clock time at which this rundown item completed playout. Used alongside actual_start_time to compute actual_duration_seconds and to validate show overrun or underrun conditions.',
    `actual_start_time` TIMESTAMP COMMENT 'Actual wall-clock time at which this rundown item began playout as recorded by the Ericsson MediaFirst automation system. Used for as-run log generation and Wide Orbit affidavit reconciliation.',
    `ad_pod_duration_seconds` STRING COMMENT 'Total allocated duration in seconds for the ad pod break associated with this rundown item. Populated only when ad_pod_flag is true. Used for ad load compliance and Wide Orbit traffic scheduling.',
    `ad_pod_flag` BOOLEAN COMMENT 'Indicates whether this rundown item represents an Ad Pod (a group of commercial spots within a break). When true, triggers SCTE-35 cue marker insertion and Dynamic Ad Insertion (DAI) eligibility checks.',
    `ad_pod_spot_count` STRING COMMENT 'Number of individual commercial spots scheduled within this ad pod break. Used for ad load monitoring, Wide Orbit traffic log validation, and FCC childrens programming ad limit compliance.',
    `backtime_flag` BOOLEAN COMMENT 'Indicates whether this rundown item is backtimed — i.e., its start time is calculated backwards from a fixed end point (e.g., top-of-hour news break or programme end). Critical for live show timing control in Ericsson MediaFirst.',
    `blackout_flag` BOOLEAN COMMENT 'Indicates whether geographic broadcast blackout restrictions apply to this rundown item. When true, triggers blackout enforcement logic in the distribution layer per rights agreements managed in Rightsline.',
    `content_rating` STRING COMMENT 'Motion Picture Association (MPA) or TV Parental Guidelines content rating applicable to this rundown item. Used for COPPA compliance checks, watershed scheduling enforcement, and EPG advisory display.. Valid values are `TV-Y|TV-Y7|TV-G|TV-PG|TV-14|TV-MA`',
    `created_timestamp` TIMESTAMP COMMENT 'Timestamp when this rundown item record was first created in the data platform, typically corresponding to the initial rundown build in Dalet Galaxy or Ericsson MediaFirst. Supports audit trail and data lineage.',
    `cue_text` STRING COMMENT 'Editorial cue or introduction text read by the presenter or director to introduce this rundown item. Stored as the production script reference for live show execution and post-broadcast archive.',
    `dalet_asset_code` STRING COMMENT 'Reference identifier for the content asset in Dalet Galaxy Media Asset Management system associated with this rundown item. Links the production element to its archived media essence, metadata, and workflow history.',
    `daypart_code` STRING COMMENT 'Code identifying the broadcast daypart (time segment of the broadcast day) in which this rundown item falls. Links to scheduling.daypart for rate multiplier, demographic targeting, and Nielsen audience measurement context.',
    `duration_variance_seconds` STRING COMMENT 'Difference in seconds between actual_duration_seconds and planned_duration_seconds (actual minus planned). Positive values indicate overrun; negative values indicate underrun. Used for show timing analysis and rundown optimisation.',
    `eom_timecode` STRING COMMENT 'SMPTE timecode marking the End of Message (EOM) — the precise out-point of the media asset for this rundown item. Used alongside som_timecode for frame-accurate duration calculation and playout control.. Valid values are `^d{2}:d{2}:d{2}[;:]d{2}$`',
    `epg_description` STRING COMMENT 'Short editorial description of this rundown item for display in the Electronic Program Guide (EPG). Populated for story packages and feature segments; used by EPG aggregators and on-screen guide systems.',
    `graphics_template_code` STRING COMMENT 'Identifier for the graphics or lower-third template to be rendered by the Ericsson MediaFirst graphics engine for this rundown item. Applicable for graphic and lower_third segment formats.',
    `isci_code` STRING COMMENT 'Industry Standard Commercial Identification (ISCI) code for the commercial spot associated with this rundown item. Populated for commercial_break items; used for Wide Orbit affidavit generation and advertiser billing reconciliation.. Valid values are `^[A-Z0-9]{8}$`',
    `item_status` STRING COMMENT 'Current production lifecycle state of the rundown item as managed in the live show production control system. Drives automation decisions in Ericsson MediaFirst and Dalet Galaxy workflow.. Valid values are `ready|on_air|completed|skipped|hold|missing`',
    `item_title` STRING COMMENT 'Human-readable editorial title or slug for the rundown item as displayed in the production control system and Electronic Program Guide (EPG). Used by producers and directors during live show execution.',
    `item_type` STRING COMMENT 'Classification of the discrete production element represented by this rundown item. Determines playout behaviour, automation triggers, and ad pod eligibility. [ENUM-REF-CANDIDATE: story_package|live_shot|interview|commercial_break|graphic|music_bed|filler|open|close — promote to reference product]',
    `live_flag` BOOLEAN COMMENT 'Indicates whether this rundown item is a live production element (true) or a pre-recorded/packaged asset (false). Drives Ericsson MediaFirst automation mode selection and EPG live indicator display.',
    `mediafirst_item_code` STRING COMMENT 'Native item identifier assigned by the Ericsson MediaFirst playout automation system for this rundown element. Used for reconciliation between the Silver Layer data product and the operational playout system.',
    `planned_duration_seconds` STRING COMMENT 'Scheduled duration of the rundown item in seconds as defined during pre-production rundown preparation. Used for total show timing, backtime calculations, and ad pod compliance checks.',
    `planned_start_time` TIMESTAMP COMMENT 'Scheduled wall-clock start time for this rundown item based on the pre-production rundown. Used for Electronic Program Guide (EPG) display, backtime calculations, and SCTE-35 cue marker pre-positioning.',
    `rights_clearance_status` STRING COMMENT 'Current rights clearance state for the content asset associated with this rundown item as verified against Rightsline. Prevents playout of uncleared content and supports compliance with windowing and holdback obligations.. Valid values are `cleared|pending|restricted|expired|not_required`',
    `scte35_cue_in_time` TIMESTAMP COMMENT 'Timestamp at which the SCTE-35 splice_insert cue-in signal is triggered to mark the return to programme content after an ad break. Used for DAI reconciliation and ad delivery verification.',
    `scte35_cue_out_time` TIMESTAMP COMMENT 'Timestamp at which the SCTE-35 splice_insert cue-out signal is triggered to mark the start of an ad break for Dynamic Ad Insertion (DAI) and addressable advertising systems. Populated for commercial_break item types.',
    `segment_format` STRING COMMENT 'Production format classification of the rundown item using broadcast newsroom terminology. Determines the technical playout configuration and graphics overlay requirements in Ericsson MediaFirst. [ENUM-REF-CANDIDATE: pkg|vo|vosot|sot|live|standup|anchor_read|graphic_full|lower_third — promote to reference product]',
    `sequence_number` STRING COMMENT 'Ordinal position of this item within the program rundown, determining the playout order. Used by Ericsson MediaFirst automation to sequence segments during live show production control.',
    `simulcast_flag` BOOLEAN COMMENT 'Indicates whether this rundown item is simultaneously broadcast across multiple platforms (linear, OTT, streaming). When true, triggers multi-platform distribution workflows and DAI configuration in Akamai CDN.',
    `skip_reason` STRING COMMENT 'Reason code explaining why this rundown item was skipped during playout. Populated only when item_status = skipped. Used for post-broadcast editorial review and rights compliance audit.. Valid values are `rights_issue|technical_fault|editorial_decision|time_overrun|duplicate|not_applicable`',
    `som_timecode` STRING COMMENT 'SMPTE timecode marking the Start of Message (SOM) — the precise in-point of the media asset to be played for this rundown item. Used by Ericsson MediaFirst for frame-accurate playout cueing.. Valid values are `^d{2}:d{2}:d{2}[;:]d{2}$`',
    `tape_number` STRING COMMENT 'Physical or virtual media identifier (tape ID, clip ID, or server ID) for the pre-recorded asset associated with this rundown item in the Dalet Galaxy MAM system. Used for media retrieval and playout server cueing.',
    `updated_timestamp` TIMESTAMP COMMENT 'Timestamp of the most recent modification to this rundown item record. Tracks editorial changes, status transitions, and timing adjustments throughout the show production lifecycle.',
    `wide_orbit_spot_code` STRING COMMENT 'Identifier from the Wide Orbit Traffic and Billing system for commercial spots or ad pod items within this rundown. Populated only for item_type = commercial_break; used for affidavit generation and billing reconciliation.',
    CONSTRAINT pk_rundown_item PRIMARY KEY(`rundown_item_id`)
) COMMENT 'Individual segment or item within a program rundown, representing a discrete production element (story package, live shot, interview, commercial break, graphic, music bed, or filler). Captures item sequence, item type, planned duration, actual duration, content asset reference, presenter/anchor assignment, cue text, backtime flag, and item status (ready, on-air, completed, skipped). The atomic unit of live show production control.';

CREATE OR REPLACE TABLE `media_broadcasting_ecm`.`scheduling`.`scheduling_availability_window` (
    `scheduling_availability_window_id` BIGINT COMMENT 'Primary key for availability_window',
    `acquisition_deal_id` BIGINT COMMENT 'Foreign key linking to partner.acquisition_deal. Business justification: Scheduling availability windows are derived from and constrained by acquisition deals; the window must reference the deal that authorized it for holdback verification, run-limit enforcement, and right',
    `asset_version_id` BIGINT COMMENT 'Foreign key linking to mediaasset.asset_version. Business justification: Platform-specific availability windows govern which asset version is cleared per territory and tier (e.g., HDR version for SVOD, SD for linear). Rights and distribution teams need version-level window',
    `channel_id` BIGINT COMMENT 'Foreign key linking to scheduling.channel. Business justification: A scheduling_availability_window defines on-demand programming windows (VOD, SVOD, AVOD, TVOD) that are often associated with a specific channels content library or catch-up service. Linking scheduli',
    `delivery_channel_id` BIGINT COMMENT 'Foreign key linking to distribution.delivery_channel. Business justification: Availability windows govern which delivery channels can carry content during a given period. Rights and distribution ops teams enforce holdback and exclusivity rules per delivery channel using availab',
    `drm_policy_id` BIGINT COMMENT 'Foreign key linking to distribution.drm_policy. Business justification: Availability windows specify DRM requirements (drm_required boolean exists but no FK to actual policy). Linking to drm_policy enables automated DRM enforcement during windowing and supports rights com',
    `market_coverage_id` BIGINT COMMENT 'Foreign key linking to audience.market_coverage. Business justification: Scheduling availability windows are market/territory scoped — blackout enforcement and rights windowing vary by DMA. The territory_code and territory_scope plain columns are denormalized market data; ',
    `media_asset_id` BIGINT COMMENT 'Foreign key linking to mediaasset.media_asset. Business justification: Distribution windows apply to specific media assets (master files, localized versions, format variants) not just title-level metadata. Rights management requires asset-level tracking for DRM applicati',
    `regulatory_obligation_id` BIGINT COMMENT 'Foreign key linking to compliance.regulatory_obligation. Business justification: Scheduling availability windows are directly governed by regulatory obligations — COPPA-restricted windows, FCC childrens programming safe harbor, and must-carry mandates. Compliance teams audit whic',
    `revenue_stream_id` BIGINT COMMENT 'Foreign key linking to finance.revenue_stream. Business justification: Availability windows define the commercial terms under which content is monetized (SVOD, AVOD, linear, EST). Finance associates each window with a revenue stream for revenue projection, recognition me',
    `rights_availability_window_id` BIGINT COMMENT 'Reference to the corresponding rights window record in the rights and licensing domain (Rightsline), linking operational scheduling parameters to the underlying contractual rights availability.',
    `series_id` BIGINT COMMENT 'Foreign key linking to content.series. Business justification: Series-level availability windows (entire series available on a platform for a defined period) are a standard content licensing and scheduling concept. Linking enables series-level window management, ',
    `subscription_plan_id` BIGINT COMMENT 'Foreign key linking to subscriber.subscription_plan. Business justification: Content availability windows are gated by subscription plan tier in OTT operations — e.g., a Premium-only window restricts access to Premium plan subscribers. This FK replaces the denormalized service',
    `title_id` BIGINT COMMENT 'Reference to the content title for which this availability window is defined. Links to the master content asset record in the content domain.',
    `version_id` BIGINT COMMENT 'Foreign key linking to content.version. Business justification: Platform-specific availability windows often apply to specific versions only (e.g., only the HD version, only the dubbed version available on a given platform). Version-level windowing is a real opera',
    `ad_break_max_duration_seconds` STRING COMMENT 'The maximum allowable duration in seconds for a single ad break (ad pod) within the content during this availability window. Used to enforce ad load limits and viewer experience standards on AVOD and FAST platforms.',
    `ad_pod_max_count` STRING COMMENT 'The maximum number of ad pods (groups of ads in a break) permitted within the content during this availability window. Governs ad load compliance for AVOD and FAST platforms. Null for SVOD or TVOD windows where advertising is not applicable.',
    `akamai_stream_url` STRING COMMENT 'The Akamai CDN origin stream URL for delivering the content during this availability window. Specifies the endpoint used for HLS or MPEG-DASH adaptive bitrate streaming to end-user devices.. Valid values are `^https://[a-zA-Z0-9._/-]+$`',
    `approved_by` STRING COMMENT 'The name or identifier of the scheduling or rights operations personnel who approved this availability window configuration for activation. Required for audit trail and compliance with rights clearance workflows.',
    `approved_timestamp` TIMESTAMP COMMENT 'The date and time at which this availability window configuration was formally approved for activation. Part of the lifecycle audit trail for rights and scheduling compliance.',
    `blackout_flag` BOOLEAN COMMENT 'Indicates whether a geographic blackout restriction applies to this availability window. When True, the content must be blocked from delivery in the specified territory, typically due to sports rights, retransmission consent, or must-carry obligations.',
    `content_rating` STRING COMMENT 'The audience content rating assigned to the title for this availability window, used to enforce age-gating, parental controls, and COPPA compliance on the platform. Follows MPA and TV Parental Guidelines rating systems. [ENUM-REF-CANDIDATE: G|PG|PG-13|R|NC-17|TV-Y|TV-Y7|TV-G|TV-PG|TV-14|TV-MA|NR — 12 candidates stripped; promote to reference product]',
    `coppa_restricted` BOOLEAN COMMENT 'Indicates whether this availability window is subject to COPPA (Childrens Online Privacy Protection Act) restrictions, requiring child-safe delivery mode, restricted data collection, and parental consent enforcement on the platform.',
    `created_timestamp` TIMESTAMP COMMENT 'The date and time at which this availability window record was first created in the system. Used for audit trail, data lineage, and compliance reporting.',
    `dai_enabled` BOOLEAN COMMENT 'Indicates whether Dynamic Ad Insertion (DAI) is enabled for this availability window. When True, server-side ad insertion is applied during streaming delivery, enabling targeted advertising for AVOD and FAST platform types.',
    `dalet_asset_code` STRING COMMENT 'The asset identifier from Dalet Galaxy Media Asset Management system corresponding to the content title in this availability window. Used to trigger ingest, metadata enrichment, and archive workflows aligned with the window schedule.. Valid values are `^[A-Z0-9_-]{3,50}$`',
    `drm_required` BOOLEAN COMMENT 'Indicates whether Digital Rights Management (DRM) protection must be enforced for content delivery during this availability window. When True, the Akamai CDN and streaming infrastructure must apply DRM encryption before delivery.',
    `eidr_code` STRING COMMENT 'The Entertainment Identifier Registry (EIDR) persistent identifier for the content title associated with this window. Enables interoperability with industry partners, distributors, and rights management systems for content identification.. Valid values are `^10.5240/[0-9A-F]{4}-[0-9A-F]{4}-[0-9A-F]{4}-[0-9A-F]{4}-[0-9A-F]{4}-[0-9A-F]{1}$`',
    `exclusive_flag` BOOLEAN COMMENT 'Indicates whether this availability window grants exclusive rights to the platform for the specified territory and window period. When True, the content must not be made available on any competing platform during this window.',
    `holdback_flag` BOOLEAN COMMENT 'Indicates whether this window represents a holdback period during which the content is explicitly withheld from the platform or service tier. When True, the content must not be made available regardless of other scheduling parameters.',
    `isan` STRING COMMENT 'The International Standard Audiovisual Number (ISAN) uniquely identifying the audiovisual work associated with this availability window. Used for cross-platform content identification, rights clearance verification, and EIDR reconciliation.. Valid values are `^ISAN [0-9A-F]{4}-[0-9A-F]{4}-[0-9A-F]{4}-[0-9A-F]{4}-[0-9A-F]{1}-[0-9A-F]{4}-[0-9A-F]{4}-[0-9A-F]{1}$`',
    `platform_type` STRING COMMENT 'Classification of the distribution platform by monetization model. SVOD = Subscription Video On Demand; AVOD = Advertising-Supported Video On Demand; TVOD = Transactional Video On Demand; FAST = Free Ad-Supported Streaming Television; MVPD = Multichannel Video Programming Distributor; vMVPD = Virtual Multichannel Video Programming Distributor.. Valid values are `SVOD|AVOD|TVOD|FAST|MVPD|vMVPD`',
    `rights_clearance_status` STRING COMMENT 'The current rights clearance verification status for this availability window. cleared means all rights have been confirmed for the platform, territory, and window period; pending means clearance is in progress; blocked means a rights conflict prevents availability; expired means rights have lapsed; not_required means no clearance is needed.. Valid values are `cleared|pending|blocked|expired|not_required`',
    `rightsline_window_ref` STRING COMMENT 'The native window reference identifier from the Rightsline Rights and Royalties Management system. Used for cross-system reconciliation between the scheduling domain and the rights domain to ensure operational parameters align with contractual rights.. Valid values are `^[A-Z0-9_-]{3,50}$`',
    `scte35_cue_enabled` BOOLEAN COMMENT 'Indicates whether SCTE-35 digital program insertion cue markers are enabled for this availability window. When True, SCTE-35 splice points are embedded in the stream to signal ad break opportunities for DAI systems.',
    `simulcast_flag` BOOLEAN COMMENT 'Indicates whether this availability window is part of a simulcast configuration, meaning the content is being delivered simultaneously across multiple platforms or channels at the same time.',
    `stagger_offset_days` STRING COMMENT 'For staggered windowing strategy, the number of days this platforms availability window is offset relative to the primary release platform or theatrical/linear premiere date. Zero indicates simultaneous release; positive values indicate delayed release.',
    `streaming_protocol` STRING COMMENT 'The adaptive bitrate (ABR) streaming protocol used to deliver the content during this availability window. HLS = HTTP Live Streaming; MPEG-DASH = Dynamic Adaptive Streaming over HTTP; SMOOTH = Microsoft Smooth Streaming; PROGRESSIVE = progressive download.. Valid values are `HLS|MPEG-DASH|HLS_DASH|SMOOTH|PROGRESSIVE`',
    `territory_code` STRING COMMENT 'ISO 3166-1 alpha-3 three-letter country code identifying the geographic territory in which this availability window applies. Used to enforce blackout obligations, retransmission consent, and territorial rights restrictions.. Valid values are `^[A-Z]{3}$`',
    `territory_scope` STRING COMMENT 'Broad geographic scope classification for the availability window. worldwide means no territorial restriction; regional means a multi-country region; national means a single country; local means a sub-national market; excluded means the territory is explicitly excluded from availability.. Valid values are `worldwide|regional|national|local|excluded`',
    `updated_timestamp` TIMESTAMP COMMENT 'The date and time at which this availability window record was last modified. Used for change tracking, incremental data pipeline processing, and audit compliance.',
    `window_close_timestamp` TIMESTAMP COMMENT 'The exact date and time (with timezone offset) at which the content title expires and is no longer available on the specified platform. Null indicates an open-ended window with no defined expiry.',
    `window_code` STRING COMMENT 'Externally-known business identifier code for this availability window, used in operational systems such as Rightsline and Dalet Galaxy for cross-system reference and reconciliation.. Valid values are `^[A-Z0-9_-]{3,40}$`',
    `window_duration_days` STRING COMMENT 'The total duration of the availability window in days, calculated as the difference between window_close_timestamp and window_open_timestamp. Stored as an operational field for scheduling and reporting purposes. Null for open-ended windows.',
    `window_notes` STRING COMMENT 'Free-text operational notes or comments associated with this availability window, capturing scheduling rationale, rights exceptions, platform-specific instructions, or escalation context for scheduling operations teams.',
    `window_open_timestamp` TIMESTAMP COMMENT 'The exact date and time (with timezone offset) at which the content title becomes available on the specified platform. This is the principal business event timestamp for the availability window lifecycle.',
    `window_status` STRING COMMENT 'Current lifecycle state of the availability window. draft indicates configuration in progress; scheduled means approved but not yet open; active means currently available to audiences; expired means the window close datetime has passed; cancelled means removed before activation; suspended means temporarily withheld.. Valid values are `draft|scheduled|active|expired|cancelled|suspended`',
    `windowing_strategy` STRING COMMENT 'The sequential release strategy applied to this availability window. day_and_date means simultaneous release across all platforms; staggered means delayed release relative to another platform; exclusive means available only on this platform for the window duration; holdback means content is withheld from this platform during the window; rolling means a continuously refreshed window; simultaneous means released at the same time as theatrical or linear broadcast.. Valid values are `day_and_date|staggered|exclusive|holdback|rolling|simultaneous`',
    CONSTRAINT pk_scheduling_availability_window PRIMARY KEY(`scheduling_availability_window_id`)
) COMMENT 'Defines the on-demand programming window configuration for VOD, SVOD, AVOD, and TVOD platforms — specifying when a content title becomes available and when it expires on each platform or service tier. Captures content reference, platform type (SVOD, AVOD, TVOD, FAST), window open datetime, window close datetime, holdback flag, geographic territory, and windowing strategy (day-and-date, staggered, exclusive). Complements rights windows from the rights domain with operational scheduling parameters.';

